 15ŌåÆ/**
 16ŌåÆ * SessionRepository ŌĆö CRUD for training sessions and modules with
 17ŌåÆ * optimistic concurrency via version counters.
 18ŌåÆ */
 19ŌåÆ
 20ŌåÆimport type { StorageAdapter } from "../storage/adapter.js";
 21ŌåÆimport type { TrainingModule, TrainingSession } from "./types.js";
 22ŌåÆ
 23ŌåÆ// ---------------------------------------------------------------------------
 24ŌåÆ// Constants
 25ŌåÆ// ---------------------------------------------------------------------------
 26ŌåÆ
 27ŌåÆconst SESSIONS_COLLECTION = "training_sessions";
 28ŌåÆconst MODULES_COLLECTION = "training_modules";
 29ŌåÆ
 30ŌåÆ/**
 31ŌåÆ * Terminal session statuses that indicate a session is no longer active.
 32ŌåÆ * findActiveSession filters these out in application code because the
 33ŌåÆ * StorageAdapter does not support NOT IN queries.
 34ŌåÆ */
 35ŌåÆconst TERMINAL_STATUSES: ReadonlySet<string> = new Set(["passed", "exhausted", "abandoned"]);
 36ŌåÆ
 37ŌåÆ// ---------------------------------------------------------------------------
 38ŌåÆ// Errors
 39ŌåÆ// ---------------------------------------------------------------------------
 40ŌåÆ
 41ŌåÆexport class VersionConflictError extends Error {
 42ŌåÆ  constructor(entity: string, id: string) {
 43ŌåÆ    super(`Version conflict: ${entity} '${id}' was modified by another request`);
 44ŌåÆ    this.name = "VersionConflictError";
 45ŌåÆ  }
 46ŌåÆ}
 47ŌåÆ
 48ŌåÆ// ---------------------------------------------------------------------------
 49ŌåÆ// Repository
 50ŌåÆ// ---------------------------------------------------------------------------
 51ŌåÆ
 52ŌåÆexport class SessionRepository {
 53ŌåÆ  constructor(private readonly storage: StorageAdapter) {}
 54ŌåÆ
 55ŌåÆ  /**
 56ŌåÆ   * Create a new training session record.
 57ŌåÆ   */
 58ŌåÆ  async createSession(
 59ŌåÆ    tenantId: string,
 60ŌåÆ    data: Omit<TrainingSession, "id">,
 61ŌåÆ  ): Promise<TrainingSession> {
 62ŌåÆ    return this.storage.create<Omit<TrainingSession, "id">>(
 63ŌåÆ      tenantId,
 64ŌåÆ      SESSIONS_COLLECTION,
 65ŌåÆ      data,
 66ŌåÆ    ) as Promise<TrainingSession>;
 67ŌåÆ  }
 68ŌåÆ
 69ŌåÆ  /**
 70ŌåÆ   * Find the active (non-terminal) session for the given employee.
 71ŌåÆ   * Terminal statuses (passed, exhausted, abandoned) are filtered out
 72ŌåÆ   * in application code because the StorageAdapter does not support NOT IN.
 73ŌåÆ   */
 74ŌåÆ  async findActiveSession(tenantId: string, employeeId: string): Promise<TrainingSession | null> {
 75ŌåÆ    const sessions = await this.storage.findMany<TrainingSession>(tenantId, SESSIONS_COLLECTION, {
 76ŌåÆ      where: { employeeId },
 77ŌåÆ    });
 78ŌåÆ
 79ŌåÆ    const active = sessions.find((s) => !TERMINAL_STATUSES.has(s.status));
 80ŌåÆ    return active ?? null;
 81ŌåÆ  }
 82ŌåÆ
 83ŌåÆ  /**
 84ŌåÆ   * Return all sessions for an employee ordered by createdAt descending.
 85ŌåÆ   */
 86ŌåÆ  async findSessionHistory(
 87ŌåÆ    tenantId: string,
 88ŌåÆ    employeeId: string,
 89ŌåÆ    options?: { limit?: number; offset?: number },
 90ŌåÆ  ): Promise<TrainingSession[]> {
 91ŌåÆ    return this.storage.findMany<TrainingSession>(tenantId, SESSIONS_COLLECTION, {
 92ŌåÆ      where: { employeeId },
 93ŌåÆ      orderBy: [{ field: "createdAt", direction: "desc" }],
 94ŌåÆ      ...(options?.limit !== undefined ? { limit: options.limit } : {}),
 95ŌåÆ      ...(options?.offset !== undefined ? { offset: options.offset } : {}),
 96ŌåÆ    });
 97ŌåÆ  }
 98ŌåÆ
 99ŌåÆ  /**
100ŌåÆ   * Update session fields with optimistic concurrency.
101ŌåÆ   * Throws VersionConflictError if the current version does not match expectedVersion.
102ŌåÆ   *
103ŌåÆ   * The read-check-write sequence is wrapped in a storage transaction so that
104ŌåÆ   * concurrent callers cannot interleave between the findById and update steps
105ŌåÆ   * (eliminates the TOCTOU race condition).
106ŌåÆ   */
107ŌåÆ  async updateSession(
108ŌåÆ    tenantId: string,
109ŌåÆ    sessionId: string,
110ŌåÆ    data: Partial<TrainingSession>,
111ŌåÆ    expectedVersion: number,
112ŌåÆ  ): Promise<TrainingSession> {
113ŌåÆ    return this.storage.transaction<TrainingSession>(tenantId, async (tx) => {
114ŌåÆ      const existing = await tx.findById<TrainingSession>(tenantId, SESSIONS_COLLECTION, sessionId);
115ŌåÆ
116ŌåÆ      if (existing === null || existing.version !== expectedVersion) {
117ŌåÆ        throw new VersionConflictError("TrainingSession", sessionId);
118ŌåÆ      }
119ŌåÆ
120ŌåÆ      return tx.update<TrainingSession>(tenantId, SESSIONS_COLLECTION, sessionId, {
121ŌåÆ        ...data,
122ŌåÆ        version: existing.version + 1,
123ŌåÆ        updatedAt: new Date().toISOString(),
124ŌåÆ      });
125ŌåÆ    });
126ŌåÆ  }
127ŌåÆ
128ŌåÆ  /**
129ŌåÆ   * Create multiple module records in sequence.
130ŌåÆ   * Returns the created modules with ids assigned by the storage layer.
131ŌåÆ   */
132ŌåÆ  async createModules(
133ŌåÆ    tenantId: string,
134ŌåÆ    modules: Array<Omit<TrainingModule, "id">>,
135ŌåÆ  ): Promise<TrainingModule[]> {
136ŌåÆ    const results: TrainingModule[] = [];
137ŌåÆ    for (const mod of modules) {
138ŌåÆ      const created = await this.storage.create<Omit<TrainingModule, "id">>(
139ŌåÆ        tenantId,
140ŌåÆ        MODULES_COLLECTION,
141ŌåÆ        mod,
142ŌåÆ      );
143ŌåÆ      results.push(created as TrainingModule);
144ŌåÆ    }
145ŌåÆ    return results;
146ŌåÆ  }
147ŌåÆ
148ŌåÆ  /**
149ŌåÆ   * Return all modules for a session ordered by moduleIndex ascending.
150ŌåÆ   */
151ŌåÆ  async findModulesBySession(tenantId: string, sessionId: string): Promise<TrainingModule[]> {
152ŌåÆ    return this.storage.findMany<TrainingModule>(tenantId, MODULES_COLLECTION, {
153ŌåÆ      where: { sessionId },
154ŌåÆ      orderBy: [{ field: "moduleIndex", direction: "asc" }],
155ŌåÆ    });
156ŌåÆ  }
157ŌåÆ
158ŌåÆ  /**
159ŌåÆ   * Find a specific module by session and zero-based index.
160ŌåÆ   * Returns null when no matching module exists.
161ŌåÆ   */
162ŌåÆ  async findModule(
163ŌåÆ    tenantId: string,
164ŌåÆ    sessionId: string,
165ŌåÆ    moduleIndex: number,
166ŌåÆ  ): Promise<TrainingModule | null> {
167ŌåÆ    const results = await this.storage.findMany<TrainingModule>(tenantId, MODULES_COLLECTION, {
168ŌåÆ      where: { sessionId, moduleIndex },
169ŌåÆ      limit: 1,
170ŌåÆ    });
171ŌåÆ    return results[0] ?? null;
172ŌåÆ  }
173ŌåÆ
174ŌåÆ  /**
175ŌåÆ   * Update module fields with optimistic concurrency.
176ŌåÆ   * Throws VersionConflictError if the current version does not match expectedVersion.
177ŌåÆ   *
178ŌåÆ   * The read-check-write sequence is wrapped in a storage transaction so that
179ŌåÆ   * concurrent callers cannot interleave between the findById and update steps
180ŌåÆ   * (eliminates the TOCTOU race condition).
181ŌåÆ   */
182ŌåÆ  async updateModule(
183ŌåÆ    tenantId: string,
184ŌåÆ    moduleId: string,
185ŌåÆ    data: Partial<TrainingModule>,
186ŌåÆ    expectedVersion: number,
187ŌåÆ  ): Promise<TrainingModule> {
188ŌåÆ    return this.storage.transaction<TrainingModule>(tenantId, async (tx) => {
189ŌåÆ      const existing = await tx.findById<TrainingModule>(tenantId, MODULES_COLLECTION, moduleId);
190ŌåÆ
191ŌåÆ      if (existing === null || existing.version !== expectedVersion) {
192ŌåÆ        throw new VersionConflictError("TrainingModule", moduleId);
193ŌåÆ      }
194ŌåÆ
195ŌåÆ      return tx.update<TrainingModule>(tenantId, MODULES_COLLECTION, moduleId, {
196ŌåÆ        ...data,
197ŌåÆ        version: existing.version + 1,
198ŌåÆ        updatedAt: new Date().toISOString(),
199ŌåÆ      });
200ŌåÆ    });
201ŌåÆ  }
202ŌåÆ}
