 15ŌåÆ/**
 16ŌåÆ * Evaluation API route.
 17ŌåÆ * POST /api/training/{tenant}/evaluate
 18ŌåÆ * Computes the final pass/fail decision for a training session in `evaluating` state.
 19ŌåÆ */
 20ŌåÆ
 21ŌåÆimport { getSnapshot } from "@/config/index";
 22ŌåÆimport { generateEvidenceForSession } from "@/evidence/evidence-generator";
 23ŌåÆimport { SQLiteAdapter } from "@/storage/sqlite-adapter";
 24ŌåÆimport { logEvaluationCompleted, logSessionExhausted } from "@/training/audit";
 25ŌåÆimport { computeAggregateScore, identifyWeakAreas, isPassing } from "@/training/score-calculator";
 26ŌåÆimport { SessionRepository, VersionConflictError } from "@/training/session-repository";
 27ŌåÆimport { StateTransitionError, transitionSession } from "@/training/state-machine";
 28ŌåÆimport { NextResponse } from "next/server";
 29ŌåÆ
 30ŌåÆexport async function POST(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
 31ŌåÆ  const { tenant: tenantSlug } = await params;
 32ŌåÆ  const tenantId = request.headers.get("x-tenant-id");
 33ŌåÆ  const employeeId = request.headers.get("x-employee-id");
 34ŌåÆ
 35ŌåÆ  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
 36ŌåÆ    return NextResponse.json(
 37ŌåÆ      { error: "unauthorized", message: "Not authenticated" },
 38ŌåÆ      { status: 401 },
 39ŌåÆ    );
 40ŌåÆ  }
 41ŌåÆ
 42ŌåÆ  // Initialise repositories per-request to avoid connection sharing
 43ŌåÆ  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 44ŌåÆ  const sessionRepo = new SessionRepository(storage);
 45ŌåÆ
 46ŌåÆ  await storage.initialize();
 47ŌåÆ
 48ŌåÆ  try {
 49ŌåÆ    // Find active session
 50ŌåÆ    const session = await sessionRepo.findActiveSession(tenantId, employeeId);
 51ŌåÆ    if (!session) {
 52ŌåÆ      return NextResponse.json(
 53ŌåÆ        { error: "not_found", message: "No active training session found" },
 54ŌåÆ        { status: 404 },
 55ŌåÆ      );
 56ŌåÆ    }
 57ŌåÆ
 58ŌåÆ    // Guard: session must be in evaluating state
 59ŌåÆ    if (session.status !== "evaluating") {
 60ŌåÆ      return NextResponse.json(
 61ŌåÆ        {
 62ŌåÆ          error: "conflict",
 63ŌåÆ          message: `Session is in '${session.status}' state, expected 'evaluating'`,
 64ŌåÆ        },
 65ŌåÆ        { status: 409 },
 66ŌåÆ      );
 67ŌåÆ    }
 68ŌåÆ
 69ŌåÆ    // Find all modules
 70ŌåÆ    const modules = await sessionRepo.findModulesBySession(tenantId, session.id);
 71ŌåÆ
 72ŌåÆ    // Extract module scores ŌĆö all must be non-null before computing aggregate
 73ŌåÆ    const rawScores = modules.map((m) => m.moduleScore);
 74ŌåÆ    if (rawScores.some((s) => s === null || s === undefined)) {
 75ŌåÆ      return NextResponse.json(
 76ŌåÆ        { error: "conflict", message: "Not all modules have been scored" },
 77ŌåÆ        { status: 409 },
 78ŌåÆ      );
 79ŌåÆ    }
 80ŌåÆ    const moduleScores = rawScores as number[];
 81ŌåÆ
 82ŌåÆ    // Compute aggregate score
 83ŌåÆ    const aggregateScore = computeAggregateScore(moduleScores) ?? 0;
 84ŌåÆ
 85ŌåÆ    // Get tenant training config
 86ŌåÆ    const snapshot = getSnapshot();
 87ŌåÆ    const tenant = snapshot?.tenants.get(tenantId);
 88ŌåÆ    const trainingConfig = tenant?.settings?.training;
 89ŌåÆ    const passThreshold = trainingConfig?.passThreshold ?? 0.7;
 90ŌåÆ    const maxAttempts = trainingConfig?.maxAttempts ?? 3;
 91ŌåÆ
 92ŌåÆ    const now = new Date().toISOString();
 93ŌåÆ    let nextAction: "complete" | "remediation-available" | "exhausted";
 94ŌåÆ    let passed: boolean;
 95ŌåÆ    let newStatus: "passed" | "failed" | "exhausted";
 96ŌåÆ    let completedAt: string | null = null;
 97ŌåÆ    let weakAreas: string[] | undefined;
 98ŌåÆ
 99ŌåÆ    if (isPassing(aggregateScore, passThreshold)) {
100ŌåÆ      // Pass
101ŌåÆ      passed = true;
102ŌåÆ      newStatus = "passed";
103ŌåÆ      nextAction = "complete";
104ŌåÆ      completedAt = now;
105ŌåÆ    } else if (session.attemptNumber < maxAttempts) {
106ŌåÆ      // Failed with attempts remaining
107ŌåÆ      passed = false;
108ŌåÆ      newStatus = "failed";
109ŌåÆ      nextAction = "remediation-available";
110ŌåÆ      weakAreas = identifyWeakAreas(
111ŌåÆ        modules.map((m) => ({ topicArea: m.topicArea, moduleScore: m.moduleScore as number })),
112ŌåÆ        passThreshold,
113ŌåÆ      );
114ŌåÆ    } else {
115ŌåÆ      // Failed and exhausted all attempts
116ŌåÆ      passed = false;
117ŌåÆ      newStatus = "exhausted";
118ŌåÆ      nextAction = "exhausted";
119ŌåÆ      completedAt = now;
120ŌåÆ    }
121ŌåÆ
122ŌåÆ    // Transition session state
123ŌåÆ    try {
124ŌåÆ      transitionSession(
125ŌåÆ        session.status,
126ŌåÆ        `evaluation-${newStatus}` as Parameters<typeof transitionSession>[1],
127ŌåÆ      );
128ŌåÆ    } catch (err) {
129ŌåÆ      if (err instanceof StateTransitionError) {
130ŌåÆ        return NextResponse.json({ error: "conflict", message: err.message }, { status: 409 });
131ŌåÆ      }
132ŌåÆ      throw err;
133ŌåÆ    }
134ŌåÆ
135ŌåÆ    // Update session
136ŌåÆ    const updateData: Parameters<typeof sessionRepo.updateSession>[2] = {
137ŌåÆ      status: newStatus,
138ŌåÆ      aggregateScore,
139ŌåÆ      ...(weakAreas !== undefined ? { weakAreas } : {}),
140ŌåÆ      ...(completedAt !== null ? { completedAt } : {}),
141ŌåÆ    };
142ŌåÆ
143ŌåÆ    try {
144ŌåÆ      await sessionRepo.updateSession(tenantId, session.id, updateData, session.version);
145ŌåÆ    } catch (err) {
146ŌåÆ      if (err instanceof VersionConflictError) {
147ŌåÆ        return NextResponse.json(
148ŌåÆ          { error: "conflict", message: "Session was modified by another request" },
149ŌåÆ          { status: 409 },
150ŌåÆ        );
151ŌåÆ      }
152ŌåÆ      throw err;
153ŌåÆ    }
154ŌåÆ
155ŌåÆ    // Audit logging
156ŌåÆ    await logEvaluationCompleted(
157ŌåÆ      storage,
158ŌåÆ      tenantId,
159ŌåÆ      employeeId,
160ŌåÆ      session.id,
161ŌåÆ      session.attemptNumber,
162ŌåÆ      aggregateScore,
163ŌåÆ      passed,
164ŌåÆ    );
165ŌåÆ
166ŌåÆ    if (newStatus === "exhausted") {
167ŌåÆ      await logSessionExhausted(
168ŌåÆ        storage,
169ŌåÆ        tenantId,
170ŌåÆ        employeeId,
171ŌåÆ        session.id,
172ŌåÆ        aggregateScore,
173ŌåÆ        session.attemptNumber,
174ŌåÆ      );
175ŌåÆ    }
176ŌåÆ
177ŌåÆ    // Fire-and-forget evidence generation for terminal states (uses its own storage connection)
178ŌåÆ    if (newStatus === "passed" || newStatus === "exhausted") {
179ŌåÆ      generateEvidenceForSession(tenantId, session.id).catch((err) =>
180ŌåÆ        console.error("Evidence generation failed:", err),
181ŌåÆ      );
182ŌåÆ    }
183ŌåÆ
184ŌåÆ    return NextResponse.json(
185ŌåÆ      {
186ŌåÆ        sessionId: session.id,
187ŌåÆ        aggregateScore,
188ŌåÆ        passed,
189ŌåÆ        attemptNumber: session.attemptNumber,
190ŌåÆ        ...(weakAreas !== undefined ? { weakAreas } : {}),
191ŌåÆ        nextAction,
192ŌåÆ      },
193ŌåÆ      { status: 200 },
194ŌåÆ    );
195ŌåÆ  } finally {
196ŌåÆ    await storage.close();
197ŌåÆ  }
198ŌåÆ}
