 15ŌåÆ/**
 16ŌåÆ * Quiz submission API route.
 17ŌåÆ * POST /api/training/{tenant}/module/{moduleIndex}/quiz
 18ŌåÆ * Accepts all quiz answers, scores them, and finalises the training module.
 19ŌåÆ */
 20ŌåÆ
 21ŌåÆimport { getSnapshot } from "@/config/index";
 22ŌåÆimport { resolveModel } from "@/intake/ai-model-resolver";
 23ŌåÆimport { SQLiteAdapter } from "@/storage/sqlite-adapter";
 24ŌåÆimport { logModuleCompleted, logQuizSubmitted } from "@/training/audit";
 25ŌåÆimport { EvaluationError, evaluateFreeText } from "@/training/evaluator";
 26ŌåÆimport { MAX_MODULE_INDEX, QuizSubmissionSchema } from "@/training/schemas";
 27ŌåÆimport { computeModuleScore, scoreMcAnswer } from "@/training/score-calculator";
 28ŌåÆimport { SessionRepository, VersionConflictError } from "@/training/session-repository";
 29ŌåÆimport { transitionModule, transitionSession } from "@/training/state-machine";
 30ŌåÆimport { NextResponse } from "next/server";
 31ŌåÆ
 32ŌåÆexport async function POST(
 33ŌåÆ  request: Request,
 34ŌåÆ  { params }: { params: Promise<{ tenant: string; moduleIndex: string }> },
 35ŌåÆ) {
 36ŌåÆ  const { tenant, moduleIndex: moduleIndexStr } = await params;
 37ŌåÆ  const tenantId = request.headers.get("x-tenant-id");
 38ŌåÆ  const employeeId = request.headers.get("x-employee-id");
 39ŌåÆ
 40ŌåÆ  // 1. Auth check
 41ŌåÆ  if (!tenantId || !employeeId || tenantId !== tenant) {
 42ŌåÆ    return NextResponse.json(
 43ŌåÆ      { error: "unauthorized", message: "Not authenticated" },
 44ŌåÆ      { status: 401 },
 45ŌåÆ    );
 46ŌåÆ  }
 47ŌåÆ
 48ŌåÆ  // 2. Parse and validate moduleIndex (0-19)
 49ŌåÆ  const moduleIndex = Number.parseInt(moduleIndexStr, 10);
 50ŌåÆ  if (Number.isNaN(moduleIndex) || moduleIndex < 0 || moduleIndex > MAX_MODULE_INDEX) {
 51ŌåÆ    return NextResponse.json(
 52ŌåÆ      { error: "validation_error", message: "moduleIndex must be an integer between 0 and 19" },
 53ŌåÆ      { status: 400 },
 54ŌåÆ    );
 55ŌåÆ  }
 56ŌåÆ
 57ŌåÆ  // 3. Parse request body
 58ŌåÆ  let body: unknown;
 59ŌåÆ  try {
 60ŌåÆ    body = await request.json();
 61ŌåÆ  } catch {
 62ŌåÆ    return NextResponse.json(
 63ŌåÆ      { error: "invalid_request", message: "Invalid JSON body" },
 64ŌåÆ      { status: 400 },
 65ŌåÆ    );
 66ŌåÆ  }
 67ŌåÆ
 68ŌåÆ  const parsed = QuizSubmissionSchema.safeParse(body);
 69ŌåÆ  if (!parsed.success) {
 70ŌåÆ    return NextResponse.json(
 71ŌåÆ      { error: "validation_error", message: "Invalid quiz submission data" },
 72ŌåÆ      { status: 400 },
 73ŌåÆ    );
 74ŌåÆ  }
 75ŌåÆ
 76ŌåÆ  const submission = parsed.data;
 77ŌåÆ
 78ŌåÆ  // Initialise repositories
 79ŌåÆ  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 80ŌåÆ  const sessionRepo = new SessionRepository(storage);
 81ŌåÆ
 82ŌåÆ  await storage.initialize();
 83ŌåÆ
 84ŌåÆ  try {
 85ŌåÆ    // 4. Find active session
 86ŌåÆ    const session = await sessionRepo.findActiveSession(tenantId, employeeId);
 87ŌåÆ    if (!session) {
 88ŌåÆ      return NextResponse.json(
 89ŌåÆ        { error: "not_found", message: "No active training session found" },
 90ŌåÆ        { status: 404 },
 91ŌåÆ      );
 92ŌåÆ    }
 93ŌåÆ
 94ŌåÆ    // Find the module
 95ŌåÆ    const mod = await sessionRepo.findModule(tenantId, session.id, moduleIndex);
 96ŌåÆ    if (!mod) {
 97ŌåÆ      return NextResponse.json(
 98ŌåÆ        { error: "not_found", message: "Module not found" },
 99ŌåÆ        { status: 404 },
100ŌåÆ      );
101ŌåÆ    }
102ŌåÆ
103ŌåÆ    // 5. Guard: module must be in `quiz-active` state
104ŌåÆ    if (mod.status !== "quiz-active") {
105ŌåÆ      return NextResponse.json(
106ŌåÆ        {
107ŌåÆ          error: "conflict",
108ŌåÆ          message: `Module is in '${mod.status}' state; expected 'quiz-active'`,
109ŌåÆ        },
110ŌåÆ        { status: 409 },
111ŌåÆ      );
112ŌåÆ    }
113ŌåÆ
114ŌåÆ    if (!mod.content) {
115ŌåÆ      return NextResponse.json(
116ŌåÆ        { error: "not_found", message: "Module content not available" },
117ŌåÆ        { status: 404 },
118ŌåÆ      );
119ŌåÆ    }
120ŌåÆ
121ŌåÆ    // 6. Validate all quiz questions are answered
122ŌåÆ    const expectedCount = mod.content.quiz.questions.length;
123ŌåÆ    if (submission.answers.length !== expectedCount) {
124ŌåÆ      return NextResponse.json(
125ŌåÆ        {
126ŌåÆ          error: "validation_error",
127ŌåÆ          message: `Expected ${expectedCount} answers but received ${submission.answers.length}`,
128ŌåÆ        },
129ŌåÆ        { status: 400 },
130ŌåÆ      );
131ŌåÆ    }
132ŌåÆ
133ŌåÆ    // Resolve AI model upfront if any free-text answers exist
134ŌåÆ    const hasFreeText = submission.answers.some((a) => a.responseType === "free-text");
135ŌåÆ    let model: ReturnType<typeof resolveModel> | undefined;
136ŌåÆ
137ŌåÆ    if (hasFreeText) {
138ŌåÆ      const snapshot = getSnapshot();
139ŌåÆ      const tenantConfig = snapshot?.tenants.get(tenantId);
140ŌåÆ      if (!tenantConfig) {
141ŌåÆ        return NextResponse.json(
142ŌåÆ          { error: "not_found", message: "Tenant configuration not found" },
143ŌåÆ          { status: 404 },
144ŌåÆ        );
145ŌåÆ      }
146ŌåÆ      model = resolveModel(tenantConfig);
147ŌåÆ    }
148ŌåÆ
149ŌåÆ    // 7. Score each answer
150ŌåÆ    const now = new Date().toISOString();
151ŌåÆ    const quizAnswers: Array<{
152ŌåÆ      questionId: string;
153ŌåÆ      responseType: "multiple-choice" | "free-text";
154ŌåÆ      selectedOption?: string;
155ŌåÆ      freeTextResponse?: string;
156ŌåÆ      score: number;
157ŌåÆ      llmRationale?: string;
158ŌåÆ      submittedAt: string;
159ŌåÆ    }> = [];
160ŌåÆ
161ŌåÆ    try {
162ŌåÆ      for (const answer of submission.answers) {
163ŌåÆ        const question = mod.content.quiz.questions.find((q) => q.id === answer.questionId);
164ŌåÆ        if (!question) {
165ŌåÆ          return NextResponse.json(
166ŌåÆ            { error: "validation_error", message: `Unknown question id '${answer.questionId}'` },
167ŌåÆ            { status: 400 },
168ŌåÆ          );
169ŌåÆ        }
170ŌåÆ
171ŌåÆ        let score: number;
172ŌåÆ        let llmRationale: string | undefined;
173ŌåÆ
174ŌåÆ        if (answer.responseType === "multiple-choice") {
175ŌåÆ          if (answer.selectedOption === undefined) {
176ŌåÆ            return NextResponse.json(
177ŌåÆ              {
178ŌåÆ                error: "validation_error",
179ŌåÆ                message: `selectedOption is required for multiple-choice question '${answer.questionId}'`,
180ŌåÆ              },
181ŌåÆ              { status: 400 },
182ŌåÆ            );
183ŌåÆ          }
184ŌåÆ          const correctOption = question.options?.find((o) => o.correct)?.key;
185ŌåÆ          if (!correctOption) {
186ŌåÆ            return NextResponse.json(
187ŌåÆ              {
188ŌåÆ                error: "internal_error",
189ŌåÆ                message: `Question '${answer.questionId}' has no correct option defined`,
190ŌåÆ              },
191ŌåÆ              { status: 500 },
192ŌåÆ            );
193ŌåÆ          }
194ŌåÆ          score = scoreMcAnswer(answer.selectedOption, correctOption);
195ŌåÆ        } else {
196ŌåÆ          // free-text ŌĆö model is guaranteed to be set when hasFreeText is true
197ŌåÆ          const evaluation = await evaluateFreeText(
198ŌåÆ            question.text,
199ŌåÆ            question.rubric ?? "",
200ŌåÆ            answer.freeTextResponse ?? "",
201ŌåÆ            // biome-ignore lint/style/noNonNullAssertion: model is set whenever hasFreeText is true
202ŌåÆ            model!,
203ŌåÆ          );
204ŌåÆ          score = evaluation.score;
205ŌåÆ          llmRationale = evaluation.rationale;
206ŌåÆ        }
207ŌåÆ
208ŌåÆ        quizAnswers.push({
209ŌåÆ          questionId: answer.questionId,
210ŌåÆ          responseType: answer.responseType,
211ŌåÆ          ...(answer.selectedOption !== undefined ? { selectedOption: answer.selectedOption } : {}),
212ŌåÆ          ...(answer.freeTextResponse !== undefined
213ŌåÆ            ? { freeTextResponse: answer.freeTextResponse }
214ŌåÆ            : {}),
215ŌåÆ          score,
216ŌåÆ          ...(llmRationale !== undefined ? { llmRationale } : {}),
217ŌåÆ          submittedAt: now,
218ŌåÆ        });
219ŌåÆ      }
220ŌåÆ    } catch (error) {
221ŌåÆ      if (error instanceof EvaluationError) {
222ŌåÆ        return NextResponse.json(
223ŌåÆ          { error: "ai_unavailable", message: "AI evaluation service temporarily unavailable" },
224ŌåÆ          { status: 503 },
225ŌåÆ        );
226ŌåÆ      }
227ŌåÆ      return NextResponse.json(
228ŌåÆ        { error: "internal_error", message: "An unexpected error occurred during scoring" },
229ŌåÆ        { status: 500 },
230ŌåÆ      );
231ŌåÆ    }
232ŌåÆ
233ŌåÆ    // 9. Compute module score
234ŌåÆ    const scenarioScores = mod.scenarioResponses.map((r) => r.score);
235ŌåÆ    const quizScores = quizAnswers.map((a) => a.score);
236ŌåÆ    const moduleScore = computeModuleScore(scenarioScores, quizScores) ?? 0;
237ŌåÆ
238ŌåÆ    // 10. Transition module to `scored`
239ŌåÆ    const nextModuleStatus = transitionModule(mod.status, "quiz-scored");
240ŌåÆ
241ŌåÆ    // 11. Update module with quizAnswers and moduleScore
242ŌåÆ    try {
243ŌåÆ      await sessionRepo.updateModule(
244ŌåÆ        tenantId,
245ŌåÆ        mod.id,
246ŌåÆ        {
247ŌåÆ          status: nextModuleStatus,
248ŌåÆ          quizAnswers,
249ŌåÆ          moduleScore,
250ŌåÆ        },
251ŌåÆ        mod.version,
252ŌåÆ      );
253ŌåÆ    } catch (updateError) {
254ŌåÆ      if (updateError instanceof VersionConflictError) {
255ŌåÆ        return NextResponse.json(
256ŌåÆ          { error: "conflict", message: "Resource was modified by another request" },
257ŌåÆ          { status: 409 },
258ŌåÆ        );
259ŌåÆ      }
260ŌåÆ      throw updateError;
261ŌåÆ    }
262ŌåÆ
263ŌåÆ    // 12. Log audit events
264ŌåÆ    await logModuleCompleted(
265ŌåÆ      storage,
266ŌåÆ      tenantId,
267ŌåÆ      employeeId,
268ŌåÆ      session.id,
269ŌåÆ      moduleIndex,
270ŌåÆ      mod.title,
271ŌåÆ      moduleScore,
272ŌåÆ    );
273ŌåÆ
274ŌåÆ    const mcCount = quizAnswers.filter((a) => a.responseType === "multiple-choice").length;
275ŌåÆ    const freeTextCount = quizAnswers.filter((a) => a.responseType === "free-text").length;
276ŌåÆ    await logQuizSubmitted(
277ŌåÆ      storage,
278ŌåÆ      tenantId,
279ŌåÆ      employeeId,
280ŌåÆ      session.id,
281ŌåÆ      moduleIndex,
282ŌåÆ      quizAnswers.length,
283ŌåÆ      mcCount,
284ŌåÆ      freeTextCount,
285ŌåÆ    );
286ŌåÆ
287ŌåÆ    // 13. Check if this is the last module; if so, transition session to `evaluating`
288ŌåÆ    // Fetch the full module list once for the total count, then compute scoredCount
289ŌåÆ    // optimistically ŌĆö previously-scored modules plus the one we just transitioned ŌĆö to
290ŌåÆ    // avoid a second read that could race with the write we just committed.
291ŌåÆ    const allModules = await sessionRepo.findModulesBySession(tenantId, session.id);
292ŌåÆ    const totalModules = allModules.length;
293ŌåÆ    // Modules already in "scored" state before this request, plus 1 for the module just updated.
294ŌåÆ    const previouslyScoredCount = allModules.filter(
295ŌåÆ      (m) => m.id !== mod.id && m.status === "scored",
296ŌåÆ    ).length;
297ŌåÆ    const scoredCount = previouslyScoredCount + 1;
298ŌåÆ
299ŌåÆ    if (scoredCount === totalModules) {
300ŌåÆ      const freshSession = await sessionRepo.findActiveSession(tenantId, employeeId);
301ŌåÆ      if (!freshSession || freshSession.id !== session.id) {
302ŌåÆ        return NextResponse.json(
303ŌåÆ          { error: "conflict", message: "Resource was modified by another request" },
304ŌåÆ          { status: 409 },
305ŌåÆ        );
306ŌåÆ      }
307ŌåÆ      const nextSessionStatus = transitionSession(freshSession.status, "all-modules-scored");
308ŌåÆ      try {
309ŌåÆ        await sessionRepo.updateSession(
310ŌåÆ          tenantId,
311ŌåÆ          freshSession.id,
312ŌåÆ          { status: nextSessionStatus },
313ŌåÆ          freshSession.version,
314ŌåÆ        );
315ŌåÆ      } catch (sessionUpdateError) {
316ŌåÆ        if (sessionUpdateError instanceof VersionConflictError) {
317ŌåÆ          return NextResponse.json(
318ŌåÆ            { error: "conflict", message: "Resource was modified by another request" },
319ŌåÆ            { status: 409 },
320ŌåÆ          );
321ŌåÆ        }
322ŌåÆ        throw sessionUpdateError;
323ŌåÆ      }
324ŌåÆ    }
325ŌåÆ
326ŌåÆ    // 14. Return 200
327ŌåÆ    return NextResponse.json({
328ŌåÆ      moduleIndex,
329ŌåÆ      moduleScore,
330ŌåÆ      answers: quizAnswers.map((a) => ({
331ŌåÆ        questionId: a.questionId,
332ŌåÆ        score: a.score,
333ŌåÆ        ...(a.llmRationale !== undefined ? { rationale: a.llmRationale } : {}),
334ŌåÆ      })),
335ŌåÆ    });
336ŌåÆ  } finally {
337ŌåÆ    await storage.close();
338ŌåÆ  }
339ŌåÆ}
