15ŌåÆimport { createHash } from "node:crypto";
16ŌåÆ
17ŌåÆ/**
18ŌåÆ * Computes a SHA-256 hash of the given evidence body using canonical JSON
19ŌåÆ * (keys sorted alphabetically at every nesting level).
20ŌåÆ */
21ŌåÆexport function computeContentHash(evidenceBody: Record<string, unknown>): string {
22ŌåÆ  const canonical = JSON.stringify(evidenceBody, (_key: string, value: unknown) => {
23ŌåÆ    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
24ŌåÆ      return Object.keys(value as Record<string, unknown>)
25ŌåÆ        .sort()
26ŌåÆ        .reduce<Record<string, unknown>>((sorted, k) => {
27ŌåÆ          sorted[k] = (value as Record<string, unknown>)[k];
28ŌåÆ          return sorted;
29ŌåÆ        }, {});
30ŌåÆ    }
31ŌåÆ    return value;
32ŌåÆ  });
33ŌåÆ
34ŌåÆ  return createHash("sha256").update(canonical).digest("hex");
35ŌåÆ}
