155ŌåÆ
156ŌåÆfunction renderModuleSummaryTable(doc: PDFKit.PDFDocument, evidence: TrainingEvidence): void {
157ŌåÆ  const { modules } = evidence.evidence;
158ŌåÆ
159ŌåÆ  if (modules.length === 0) {
160ŌåÆ    return;
161ŌåÆ  }
162ŌåÆ
163ŌåÆ  sectionHeading(doc, "Module Summary");
164ŌåÆ
165ŌåÆ  const colWidths = [40, 200, 120, 80];
166ŌåÆ  const tableWidth = colWidths.reduce((a, b) => a + b, 0);
167ŌåÆ  const startX = doc.x;
168ŌåÆ
169ŌåÆ  // Header row
170ŌåÆ  doc.font("Helvetica-Bold").fontSize(FONT_SIZE_SMALL);
171ŌåÆ  let x = startX;
172ŌåÆ  const headers: string[] = ["#", "Title", "Topic Area", "Score"];
173ŌåÆ  const headerY = doc.y;
174ŌåÆ  for (let i = 0; i < headers.length; i++) {
175ŌåÆ    const w = colWidths[i] ?? 0;
176ŌåÆ    doc.text(headers[i] ?? "", x, headerY, { width: w, continued: false });
177ŌåÆ    x += w;
178ŌåÆ  }
179ŌåÆ  doc.moveDown(0.3);
180ŌåÆ
181ŌåÆ  // Thin line under header
182ŌåÆ  const lineY = doc.y;
183ŌåÆ  doc
184ŌåÆ    .moveTo(startX, lineY)
185ŌåÆ    .lineTo(startX + tableWidth, lineY)
186ŌåÆ    .lineWidth(0.5)
187ŌåÆ    .stroke();
188ŌåÆ  doc.moveDown(0.3);
189ŌåÆ
190ŌåÆ  // Data rows
191ŌåÆ  doc.font("Helvetica").fontSize(FONT_SIZE_SMALL);
192ŌåÆ  for (const mod of modules) {
193ŌåÆ    checkPageBreak(doc, 20);
194ŌåÆ    x = startX;
195ŌåÆ    const rowY = doc.y;
196ŌåÆ    const scoreStr = mod.moduleScore !== null ? `${(mod.moduleScore * 100).toFixed(1)}%` : "N/A";
197ŌåÆ    const cells: string[] = [String(mod.moduleIndex + 1), mod.title, mod.topicArea, scoreStr];
198ŌåÆ    for (let i = 0; i < cells.length; i++) {
199ŌåÆ      const w = colWidths[i] ?? 0;
200ŌåÆ      doc.text(cells[i] ?? "", x, rowY, { width: w });
201ŌåÆ      x += w;
202ŌåÆ    }
203ŌåÆ    doc.moveDown(0.2);
204ŌåÆ  }
205ŌåÆ
206ŌåÆ  doc.moveDown(0.5);
207ŌåÆ  drawHorizontalRule(doc);
208ŌåÆ}
