213ŌåÆ
214ŌåÆfunction renderQuizDetails(doc: PDFKit.PDFDocument, evidence: TrainingEvidence): void {
215ŌåÆ  const { modules } = evidence.evidence;
216ŌåÆ  const hasQuizzes = modules.some((m) => m.quizQuestions.length > 0);
217ŌåÆ
218ŌåÆ  if (!hasQuizzes) {
219ŌåÆ    return;
220ŌåÆ  }
221ŌåÆ
222ŌåÆ  sectionHeading(doc, "Quiz Details");
223ŌåÆ
224ŌåÆ  for (const mod of modules) {
