245ŌåÆ      } else if (q.responseType === "free-text" && freeTextResponse) {
246ŌåÆ        doc.text(`Response: ${freeTextResponse}`);
247ŌåÆ      }
248ŌåÆ
249ŌåÆ      doc.text(`Score: ${(q.employeeAnswer.score * 100).toFixed(1)}%`);
250ŌåÆ
251ŌåÆ      const { llmRationale } = q.employeeAnswer;
252ŌåÆ      if (llmRationale) {
