254ŌåÆ      }
255ŌåÆ
256ŌåÆ      doc.moveDown(0.5);
257ŌåÆ    }
258ŌåÆ  }
259ŌåÆ
260ŌåÆ  drawHorizontalRule(doc);
261ŌåÆ}
