295ŌåÆ
296ŌåÆ  const rows: Array<[string, string]> = [
297ŌåÆ    ["Content Hash (SHA-256)", evidence.contentHash],
298ŌåÆ    ["Schema Version", String(evidence.schemaVersion)],
299ŌåÆ    ["Evidence ID", evidence.id],
