15ŌåÆ/**
16ŌåÆ * TenantResolver ŌĆö resolves tenants from hostname or email domain.
17ŌåÆ * Precedence: hostname > emailDomain (FR-006).
18ŌåÆ * Lookups are O(1) via pre-built indexes. Case-insensitive.
19ŌåÆ */
20ŌåÆ
21ŌåÆimport type { ConfigSnapshot, Tenant, TenantResolverContext } from "./types.js";
22ŌåÆ
23ŌåÆexport class TenantResolverImpl {
24ŌåÆ  private readonly tenants: ReadonlyMap<string, Tenant>;
25ŌåÆ  private readonly hostnameIndex: ReadonlyMap<string, string>;
26ŌåÆ  private readonly emailDomainIndex: ReadonlyMap<string, string>;
27ŌåÆ
28ŌåÆ  constructor(snapshot: ConfigSnapshot) {
29ŌåÆ    this.tenants = snapshot.tenants;
30ŌåÆ    this.hostnameIndex = snapshot.hostnameIndex;
31ŌåÆ    this.emailDomainIndex = snapshot.emailDomainIndex;
32ŌåÆ  }
33ŌåÆ
34ŌåÆ  /**
35ŌåÆ   * Resolve the tenant for the given context.
36ŌåÆ   * Precedence: hostname > emailDomain.
37ŌåÆ   * Returns null if no match found.
38ŌåÆ   */
39ŌåÆ  resolve(context: TenantResolverContext): Tenant | null {
40ŌåÆ    if (context.hostname) {
41ŌåÆ      const tenantId = this.hostnameIndex.get(context.hostname.toLowerCase());
42ŌåÆ      if (tenantId) {
43ŌåÆ        return this.tenants.get(tenantId) ?? null;
44ŌåÆ      }
45ŌåÆ    }
46ŌåÆ
47ŌåÆ    if (context.emailDomain) {
48ŌåÆ      const tenantId = this.emailDomainIndex.get(context.emailDomain.toLowerCase());
49ŌåÆ      if (tenantId) {
50ŌåÆ        return this.tenants.get(tenantId) ?? null;
51ŌåÆ      }
52ŌåÆ    }
53ŌåÆ
54ŌåÆ    return null;
55ŌåÆ  }
56ŌåÆ}
57ŌåÆ
58ŌåÆ/**
59ŌåÆ * Factory function to create a TenantResolver from a ConfigSnapshot.
60ŌåÆ */
61ŌåÆexport function createResolver(snapshot: ConfigSnapshot): TenantResolverImpl {
62ŌåÆ  return new TenantResolverImpl(snapshot);
63ŌåÆ}
