 15ŌåÆ/**
 16ŌåÆ * SQLite-backed StorageAdapter implementation using better-sqlite3.
 17ŌåÆ * Constitution Principle III: Every query enforces tenant_id scoping.
 18ŌåÆ * Constitution Principle V: Pluggable Architecture.
 19ŌåÆ */
 20ŌåÆ
 21ŌåÆimport crypto from "node:crypto";
 22ŌåÆimport Database from "better-sqlite3";
 23ŌåÆimport type { StorageAdapter } from "./adapter.js";
 24ŌåÆimport type { QueryFilter, StorageMetadata, TransactionContext } from "./types.js";
 25ŌåÆ
 26ŌåÆexport interface SQLiteAdapterOptions {
 27ŌåÆ  dbPath: string;
 28ŌåÆ}
 29ŌåÆ
 30ŌåÆexport class SQLiteAdapter implements StorageAdapter {
 31ŌåÆ  private db: Database.Database;
 32ŌåÆ  private initialized = false;
 33ŌåÆ
 34ŌåÆ  constructor(options: SQLiteAdapterOptions) {
 35ŌåÆ    this.db = new Database(options.dbPath);
 36ŌåÆ    this.db.pragma("journal_mode = WAL");
 37ŌåÆ    this.db.pragma("foreign_keys = ON");
 38ŌåÆ  }
 39ŌåÆ
 40ŌåÆ  async initialize(): Promise<void> {
 41ŌåÆ    if (this.initialized) {
 42ŌåÆ      return;
 43ŌåÆ    }
 44ŌåÆ
 45ŌåÆ    this.db.exec(`
 46ŌåÆ      CREATE TABLE IF NOT EXISTS records (
 47ŌåÆ        id TEXT PRIMARY KEY,
 48ŌåÆ        tenant_id TEXT NOT NULL,
 49ŌåÆ        collection TEXT NOT NULL,
 50ŌåÆ        data TEXT NOT NULL,
 51ŌåÆ        created_at TEXT NOT NULL,
 52ŌåÆ        updated_at TEXT NOT NULL
 53ŌåÆ      );
 54ŌåÆ
 55ŌåÆ      CREATE INDEX IF NOT EXISTS idx_records_tenant_collection
 56ŌåÆ        ON records (tenant_id, collection);
 57ŌåÆ    `);
 58ŌåÆ
 59ŌåÆ    this.initialized = true;
 60ŌåÆ  }
 61ŌåÆ
 62ŌåÆ  async create<T extends Record<string, unknown>>(
 63ŌåÆ    tenantId: string,
 64ŌåÆ    collection: string,
 65ŌåÆ    data: T,
 66ŌåÆ  ): Promise<T & { id: string }> {
 67ŌåÆ    const id = crypto.randomUUID();
 68ŌåÆ    const now = new Date().toISOString();
 69ŌåÆ    const record = { ...data, id };
 70ŌåÆ
 71ŌåÆ    this.db
 72ŌåÆ      .prepare(
 73ŌåÆ        "INSERT INTO records (id, tenant_id, collection, data, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?)",
 74ŌåÆ      )
 75ŌåÆ      .run(id, tenantId, collection, JSON.stringify(record), now, now);
 76ŌåÆ
 77ŌåÆ    return record;
 78ŌåÆ  }
 79ŌåÆ
 80ŌåÆ  async findById<T>(tenantId: string, collection: string, id: string): Promise<T | null> {
 81ŌåÆ    const row = this.db
 82ŌåÆ      .prepare("SELECT data FROM records WHERE id = ? AND tenant_id = ? AND collection = ?")
 83ŌåÆ      .get(id, tenantId, collection) as { data: string } | undefined;
 84ŌåÆ
 85ŌåÆ    if (!row) {
 86ŌåÆ      return null;
 87ŌåÆ    }
 88ŌåÆ
 89ŌåÆ    return JSON.parse(row.data) as T;
 90ŌåÆ  }
 91ŌåÆ
 92ŌåÆ  async findMany<T>(tenantId: string, collection: string, query: QueryFilter): Promise<T[]> {
 93ŌåÆ    const conditions: string[] = ["tenant_id = ?", "collection = ?"];
 94ŌåÆ    const params: unknown[] = [tenantId, collection];
 95ŌåÆ
 96ŌåÆ    if (query.where) {
 97ŌåÆ      for (const [key, value] of Object.entries(query.where)) {
 98ŌåÆ        conditions.push(`json_extract(data, '$.' || ?) = ?`);
 99ŌåÆ        params.push(key, value);
100ŌåÆ      }
101ŌåÆ    }
102ŌåÆ
103ŌåÆ    let sql = `SELECT data FROM records WHERE ${conditions.join(" AND ")}`;
104ŌåÆ
105ŌåÆ    if (query.orderBy && query.orderBy.length > 0) {
106ŌåÆ      const orderClauses = query.orderBy.map((o) => {
107ŌåÆ        if (!/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(o.field)) {
108ŌåÆ          throw new Error(`Invalid order field: ${o.field}`);
109ŌåÆ        }
110ŌåÆ        const dir = o.direction === "desc" ? "DESC" : "ASC";
111ŌåÆ        return `json_extract(data, '$.' || '${o.field}') ${dir}`;
112ŌåÆ      });
113ŌåÆ      sql += ` ORDER BY ${orderClauses.join(", ")}`;
114ŌåÆ    }
115ŌåÆ
116ŌåÆ    if (query.limit !== undefined) {
117ŌåÆ      sql += " LIMIT ?";
118ŌåÆ      params.push(query.limit);
119ŌåÆ    }
120ŌåÆ
121ŌåÆ    if (query.offset !== undefined) {
122ŌåÆ      if (query.limit === undefined) {
123ŌåÆ        sql += " LIMIT -1";
124ŌåÆ      }
125ŌåÆ      sql += " OFFSET ?";
126ŌåÆ      params.push(query.offset);
127ŌåÆ    }
128ŌåÆ
129ŌåÆ    const rows = this.db.prepare(sql).all(...params) as { data: string }[];
130ŌåÆ    return rows.map((row) => JSON.parse(row.data) as T);
131ŌåÆ  }
132ŌåÆ
133ŌåÆ  async update<T extends Record<string, unknown>>(
134ŌåÆ    tenantId: string,
135ŌåÆ    collection: string,
136ŌåÆ    id: string,
137ŌåÆ    data: Partial<T>,
138ŌåÆ  ): Promise<T> {
139ŌåÆ    const existing = await this.findById<T>(tenantId, collection, id);
140ŌåÆ    if (!existing) {
141ŌåÆ      throw new Error(`Record not found: ${id} in collection ${collection} for tenant ${tenantId}`);
142ŌåÆ    }
143ŌåÆ
144ŌåÆ    const updated = { ...existing, ...data, id };
145ŌåÆ    const now = new Date().toISOString();
146ŌåÆ
147ŌåÆ    this.db
148ŌåÆ      .prepare(
149ŌåÆ        "UPDATE records SET data = ?, updated_at = ? WHERE id = ? AND tenant_id = ? AND collection = ?",
150ŌåÆ      )
151ŌåÆ      .run(JSON.stringify(updated), now, id, tenantId, collection);
152ŌåÆ
153ŌåÆ    return updated as T;
154ŌåÆ  }
155ŌåÆ
156ŌåÆ  async delete(tenantId: string, collection: string, id: string): Promise<void> {
157ŌåÆ    this.db
158ŌåÆ      .prepare("DELETE FROM records WHERE id = ? AND tenant_id = ? AND collection = ?")
159ŌåÆ      .run(id, tenantId, collection);
160ŌåÆ  }
161ŌåÆ
162ŌåÆ  async transaction<R>(_tenantId: string, fn: (tx: TransactionContext) => Promise<R>): Promise<R> {
163ŌåÆ    const txContext: TransactionContext = {
164ŌåÆ      create: <T extends Record<string, unknown>>(
165ŌåÆ        txTenantId: string,
166ŌåÆ        collection: string,
167ŌåÆ        data: T,
168ŌåÆ      ) => this.create(txTenantId, collection, data),
169ŌåÆ
170ŌåÆ      findById: <T>(txTenantId: string, collection: string, id: string) =>
171ŌåÆ        this.findById<T>(txTenantId, collection, id),
172ŌåÆ
173ŌåÆ      update: <T extends Record<string, unknown>>(
174ŌåÆ        txTenantId: string,
175ŌåÆ        collection: string,
176ŌåÆ        id: string,
177ŌåÆ        data: Partial<T>,
178ŌåÆ      ) => this.update<T>(txTenantId, collection, id, data),
179ŌåÆ
180ŌåÆ      delete: (txTenantId: string, collection: string, id: string) =>
181ŌåÆ        this.delete(txTenantId, collection, id),
182ŌåÆ    };
183ŌåÆ
184ŌåÆ    // better-sqlite3 is synchronous, so we manually manage BEGIN/COMMIT/ROLLBACK
185ŌåÆ    // to support async transaction callbacks.
186ŌåÆ    this.db.exec("BEGIN");
187ŌåÆ    try {
188ŌåÆ      const result = await fn(txContext);
189ŌåÆ      this.db.exec("COMMIT");
190ŌåÆ      return result;
191ŌåÆ    } catch (error) {
192ŌåÆ      this.db.exec("ROLLBACK");
193ŌåÆ      throw error;
194ŌåÆ    }
195ŌåÆ  }
196ŌåÆ
197ŌåÆ  getMetadata(): StorageMetadata {
198ŌåÆ    return {
199ŌåÆ      adapterName: "sqlite",
200ŌåÆ      adapterVersion: "1.0.0",
201ŌåÆ    };
202ŌåÆ  }
203ŌåÆ
204ŌåÆ  async close(): Promise<void> {
205ŌåÆ    this.db.close();
206ŌåÆ  }
207ŌåÆ}
