15ŌåÆ/**
16ŌåÆ * Manual evidence generation API route.
17ŌåÆ * POST /api/training/{tenant}/evidence/{sessionId}/generate
18ŌåÆ * Generates (or returns existing) evidence for a terminal training session.
19ŌåÆ */
20ŌåÆ
21ŌåÆimport { generateEvidenceForSession } from "@/evidence/evidence-generator";
22ŌåÆimport { EvidenceRepository } from "@/evidence/evidence-repository";
23ŌåÆimport { SQLiteAdapter } from "@/storage/sqlite-adapter";
24ŌåÆimport { NextResponse } from "next/server";
25ŌåÆ
26ŌåÆconst TERMINAL_STATUSES = new Set(["passed", "exhausted", "abandoned"]);
27ŌåÆ
28ŌåÆexport async function POST(
29ŌåÆ  request: Request,
30ŌåÆ  { params }: { params: Promise<{ tenant: string; sessionId: string }> },
31ŌåÆ) {
32ŌåÆ  const { tenant: tenantSlug, sessionId } = await params;
33ŌåÆ  const tenantId = request.headers.get("x-tenant-id");
34ŌåÆ  const employeeId = request.headers.get("x-employee-id");
35ŌåÆ
36ŌåÆ  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
37ŌåÆ    return NextResponse.json(
38ŌåÆ      { error: "unauthorized", message: "Not authenticated" },
39ŌåÆ      { status: 401 },
40ŌåÆ    );
41ŌåÆ  }
42ŌåÆ
43ŌåÆ  const role = request.headers.get("x-employee-role") ?? "employee";
44ŌåÆ  if (role === "employee") {
45ŌåÆ    return NextResponse.json(
46ŌåÆ      { error: "forbidden", message: "Admin access required" },
47ŌåÆ      { status: 403 },
48ŌåÆ    );
49ŌåÆ  }
50ŌåÆ
51ŌåÆ  const storage = new SQLiteAdapter({
52ŌåÆ    dbPath: process.env.DB_PATH ?? "data/jem.db",
53ŌåÆ  });
54ŌåÆ  await storage.initialize();
55ŌåÆ
56ŌåÆ  try {
57ŌåÆ    // Check session exists and is in terminal state
58ŌåÆ    const session = await storage.findById(tenantId, "training_sessions", sessionId);
59ŌåÆ    if (!session) {
60ŌåÆ      return NextResponse.json(
61ŌåÆ        { error: "not_found", message: "Session not found" },
62ŌåÆ        { status: 404 },
63ŌåÆ      );
64ŌåÆ    }
65ŌåÆ    if (!TERMINAL_STATUSES.has((session as Record<string, unknown>).status as string)) {
66ŌåÆ      return NextResponse.json(
67ŌåÆ        { error: "conflict", message: "Session is not in a terminal state" },
68ŌåÆ        { status: 409 },
69ŌåÆ      );
70ŌåÆ    }
71ŌåÆ
72ŌåÆ    // Check if evidence already exists (idempotent)
73ŌåÆ    const evidenceRepo = new EvidenceRepository(storage);
74ŌåÆ    const existing = await evidenceRepo.findBySessionId(tenantId, sessionId);
75ŌåÆ    if (existing) {
76ŌåÆ      return NextResponse.json(existing, { status: 200 });
77ŌåÆ    }
78ŌåÆ
79ŌåÆ    // Generate evidence (awaited, not fire-and-forget ŌĆö manages its own storage connection)
80ŌåÆ    const evidence = await generateEvidenceForSession(tenantId, sessionId);
81ŌåÆ    return NextResponse.json(evidence, { status: 201 });
82ŌåÆ  } finally {
83ŌåÆ    await storage.close();
84ŌåÆ  }
85ŌåÆ}
