 15ŌåÆ/**
 16ŌåÆ * FileConfigProvider ŌĆö reads YAML/JSON tenant configs from a local directory.
 17ŌåÆ * Constitution Principle V: Pluggable Architecture ŌĆö reference implementation.
 18ŌåÆ */
 19ŌåÆ
 20ŌåÆimport { readFile, readdir } from "node:fs/promises";
 21ŌåÆimport { join, parse as parsePath } from "node:path";
 22ŌåÆimport { parse as parseYaml } from "yaml";
 23ŌåÆimport { ConfigError } from "./errors.js";
 24ŌåÆimport type {
 25ŌåÆ  ConfigProvider,
 26ŌåÆ  FileConfigProviderOptions,
 27ŌåÆ  RawConfig,
 28ŌåÆ  RawTenantConfig,
 29ŌåÆ} from "./provider.js";
 30ŌåÆ
 31ŌåÆconst SUPPORTED_EXTENSIONS = new Set([".yaml", ".yml", ".json"]);
 32ŌåÆ
 33ŌåÆexport class FileConfigProvider implements ConfigProvider {
 34ŌåÆ  private readonly configDir: string;
 35ŌåÆ  private readonly defaultsFile: string;
 36ŌåÆ  private readonly tenantsDir: string;
 37ŌåÆ
 38ŌåÆ  constructor(options: FileConfigProviderOptions) {
 39ŌåÆ    this.configDir = options.configDir;
 40ŌåÆ    this.defaultsFile = options.defaultsFile ?? "defaults.yaml";
 41ŌåÆ    this.tenantsDir = options.tenantsDir ?? "tenants";
 42ŌåÆ  }
 43ŌåÆ
 44ŌåÆ  async loadDefaults(): Promise<RawConfig> {
 45ŌåÆ    const filePath = join(this.configDir, this.defaultsFile);
 46ŌåÆ    try {
 47ŌåÆ      const content = await readFile(filePath, "utf-8");
 48ŌåÆ      return this.parseFile(content, filePath);
 49ŌåÆ    } catch (error) {
 50ŌåÆ      if ((error as NodeJS.ErrnoException).code === "ENOENT") {
 51ŌåÆ        throw new ConfigError({
 52ŌåÆ          file: filePath,
 53ŌåÆ          message: `Defaults file not found: ${filePath}`,
 54ŌåÆ        });
 55ŌåÆ      }
 56ŌåÆ      throw error;
 57ŌåÆ    }
 58ŌåÆ  }
 59ŌåÆ
 60ŌåÆ  async loadTenants(): Promise<RawTenantConfig[]> {
 61ŌåÆ    const tenantsPath = join(this.configDir, this.tenantsDir);
 62ŌåÆ    let entries: string[];
 63ŌåÆ
 64ŌåÆ    try {
 65ŌåÆ      entries = await readdir(tenantsPath);
 66ŌåÆ    } catch (error) {
 67ŌåÆ      if ((error as NodeJS.ErrnoException).code === "ENOENT") {
 68ŌåÆ        throw new ConfigError({
 69ŌåÆ          file: tenantsPath,
 70ŌåÆ          message: `Tenants directory not found: ${tenantsPath}`,
 71ŌåÆ        });
 72ŌåÆ      }
 73ŌåÆ      throw error;
 74ŌåÆ    }
 75ŌåÆ
 76ŌåÆ    const tenantFiles = entries.filter((f) => {
 77ŌåÆ      const ext = parsePath(f).ext.toLowerCase();
 78ŌåÆ      return SUPPORTED_EXTENSIONS.has(ext);
 79ŌåÆ    });
 80ŌåÆ
 81ŌåÆ    if (tenantFiles.length === 0) {
 82ŌåÆ      throw new ConfigError({
 83ŌåÆ        file: tenantsPath,
 84ŌåÆ        message: "No tenant configuration files found in tenants directory",
 85ŌåÆ      });
 86ŌåÆ    }
 87ŌåÆ
 88ŌåÆ    const tenants: RawTenantConfig[] = [];
 89ŌåÆ    for (const file of tenantFiles.sort()) {
 90ŌåÆ      const filePath = join(tenantsPath, file);
 91ŌåÆ      const raw = await readFile(filePath, "utf-8");
 92ŌåÆ      const { name } = parsePath(file);
 93ŌåÆ      tenants.push({
 94ŌåÆ        content: this.parseFile(raw, filePath),
 95ŌåÆ        sourceFile: filePath,
 96ŌåÆ        tenantId: name,
 97ŌåÆ      });
 98ŌåÆ    }
 99ŌåÆ
100ŌåÆ    return tenants;
101ŌåÆ  }
102ŌåÆ
103ŌåÆ  /**
104ŌåÆ   * Returns the raw text content of a file (before env substitution).
105ŌåÆ   * Used by the validator to perform substitution on raw text.
106ŌåÆ   */
107ŌåÆ  async loadRawText(filePath: string): Promise<string> {
108ŌåÆ    return readFile(filePath, "utf-8");
109ŌåÆ  }
110ŌåÆ
111ŌåÆ  private parseFile(content: string, filePath: string): RawConfig {
112ŌåÆ    const ext = parsePath(filePath).ext.toLowerCase();
113ŌåÆ    try {
114ŌåÆ      if (ext === ".json") {
115ŌåÆ        return JSON.parse(content) as RawConfig;
116ŌåÆ      }
117ŌåÆ      return parseYaml(content) as RawConfig;
118ŌåÆ    } catch (error) {
119ŌåÆ      throw new ConfigError({
120ŌåÆ        file: filePath,
121ŌåÆ        message: `Failed to parse ${ext === ".json" ? "JSON" : "YAML"}: ${(error as Error).message}`,
122ŌåÆ      });
123ŌåÆ    }
124ŌåÆ  }
125ŌåÆ}
