15ŌåÆ/**
16ŌåÆ * Deterministic config hashing using SHA-256.
17ŌåÆ * Uses safe-stable-stringify for deterministic key ordering.
18ŌåÆ */
19ŌåÆ
20ŌåÆimport { createHash } from "node:crypto";
21ŌåÆimport stringify from "safe-stable-stringify";
22ŌåÆimport type { Tenant } from "../tenant/types.js";
23ŌåÆ
24ŌåÆ/**
25ŌåÆ * Compute a deterministic SHA-256 hash of the full tenant configuration.
26ŌåÆ * The hash input is never logged (security requirement).
27ŌåÆ */
28ŌåÆexport function computeConfigHash(tenants: readonly Tenant[]): string {
29ŌåÆ  const serialized = stringify(tenants);
30ŌåÆ  if (serialized === undefined) {
31ŌåÆ    throw new Error("Failed to serialize tenant configuration for hashing");
32ŌåÆ  }
33ŌåÆ  return createHash("sha256").update(serialized).digest("hex");
34ŌåÆ}
