140ŌåÆ/**
141ŌåÆ * Load config with env var substitution on raw file text.
142ŌåÆ * This is the full pipeline: read raw text ŌåÆ substitute ŌåÆ parse ŌåÆ validate ŌåÆ merge ŌåÆ hash.
143ŌåÆ */
144ŌåÆexport async function loadConfigFromFiles(
145ŌåÆ  configDir: string,
146ŌåÆ  options: LoadConfigOptions = {},
147ŌåÆ): Promise<ConfigSnapshot> {
148ŌåÆ  const { FileConfigProvider } = await import("./file-provider.js");
149ŌåÆ  const provider = new FileConfigProvider({ configDir });
150ŌåÆ  const env = options.env;
151ŌåÆ  const errors: ConfigErrorDetail[] = [];
152ŌåÆ  const allSensitiveVars = new Set<string>();
153ŌåÆ
154ŌåÆ  // Load raw text for defaults and substitute env vars
155ŌåÆ  const defaultsRaw = await provider.loadRawText(`${configDir}/defaults.yaml`);
156ŌåÆ  const defaultsSub = substituteEnvVars(defaultsRaw, `${configDir}/defaults.yaml`, env);
157ŌåÆ  for (const v of defaultsSub.sensitiveVars) allSensitiveVars.add(v);
158ŌåÆ
159ŌåÆ  const defaultsParsed = parseYaml(defaultsSub.text);
160ŌåÆ  const defaultsResult = BaseConfigSchema.safeParse(defaultsParsed);
161ŌåÆ  if (!defaultsResult.success) {
162ŌåÆ    for (const issue of defaultsResult.error.issues) {
163ŌåÆ      errors.push({
164ŌåÆ        file: `${configDir}/defaults.yaml`,
165ŌåÆ        path: issue.path.join("."),
166ŌåÆ        message: issue.message,
167ŌåÆ      });
168ŌåÆ    }
169ŌåÆ    throw new ConfigValidationError(errors);
170ŌåÆ  }
171ŌåÆ  const baseDefaults = defaultsResult.data.defaults;
172ŌåÆ
173ŌåÆ  // Load raw tenant files, substitute, parse, validate
174ŌåÆ  const rawTenants = await provider.loadTenants();
175ŌåÆ  const tenants: Tenant[] = [];
176ŌåÆ
177ŌåÆ  for (const raw of rawTenants) {
178ŌåÆ    // Re-read raw text for substitution
179ŌåÆ    const tenantRaw = await readFile(raw.sourceFile, "utf-8");
180ŌåÆ    const tenantSub = substituteEnvVars(tenantRaw, raw.sourceFile, env);
181ŌåÆ    for (const v of tenantSub.sensitiveVars) allSensitiveVars.add(v);
182ŌåÆ
183ŌåÆ    const tenantParsed = parseYaml(tenantSub.text);
184ŌåÆ    const tenantResult = TenantConfigSchema.safeParse(tenantParsed);
185ŌåÆ    if (!tenantResult.success) {
186ŌåÆ      for (const issue of tenantResult.error.issues) {
187ŌåÆ        errors.push({
188ŌåÆ          file: raw.sourceFile,
189ŌåÆ          path: issue.path.join("."),
190ŌåÆ          message: issue.message,
191ŌåÆ        });
192ŌåÆ      }
193ŌåÆ      continue;
194ŌåÆ    }
195ŌåÆ
196ŌåÆ    const data = tenantResult.data;
197ŌåÆ    const mergedSettings = deepMergeSettings(baseDefaults, data.settings);
198ŌåÆ
199ŌåÆ    tenants.push({
200ŌåÆ      id: raw.tenantId,
201ŌåÆ      name: data.name,
202ŌåÆ      hostnames: data.hostnames,
203ŌåÆ      emailDomains: data.emailDomains,
204ŌåÆ      settings: mergedSettings,
205ŌåÆ    });
206ŌåÆ  }
207ŌåÆ
208ŌåÆ  if (errors.length > 0) {
209ŌåÆ    throw new ConfigValidationError(errors);
210ŌåÆ  }
211ŌåÆ
212ŌåÆ  validateUniqueness(tenants);
213ŌåÆ
214ŌåÆ  const hostnameIndex = new Map<string, string>();
215ŌåÆ  const emailDomainIndex = new Map<string, string>();
216ŌåÆ  for (const tenant of tenants) {
217ŌåÆ    for (const hostname of tenant.hostnames) {
218ŌåÆ      hostnameIndex.set(hostname.toLowerCase(), tenant.id);
219ŌåÆ    }
220ŌåÆ    for (const domain of tenant.emailDomains) {
221ŌåÆ      emailDomainIndex.set(domain.toLowerCase(), tenant.id);
222ŌåÆ    }
223ŌåÆ  }
224ŌåÆ
225ŌåÆ  const configHash = computeConfigHash(tenants);
226ŌåÆ  const tenantsMap = new Map<string, Tenant>();
227ŌåÆ  for (const tenant of tenants) {
228ŌåÆ    tenantsMap.set(tenant.id, Object.freeze(tenant));
229ŌåÆ  }
230ŌåÆ
231ŌåÆ  const snapshot: ConfigSnapshot = Object.freeze({
232ŌåÆ    tenants: tenantsMap,
233ŌåÆ    hostnameIndex,
234ŌåÆ    emailDomainIndex,
235ŌåÆ    configHash,
236ŌåÆ    loadedAt: new Date(),
237ŌåÆ  });
238ŌåÆ
239ŌåÆ  currentSnapshot = snapshot;
240ŌåÆ  return snapshot;
241ŌåÆ}
