243ŌåÆ/**
244ŌåÆ * Get the current loaded config snapshot.
245ŌåÆ */
246ŌåÆexport function getSnapshot(): ConfigSnapshot | null {
247ŌåÆ  return currentSnapshot;
248ŌåÆ}
