 15ŌåÆ/**
 16ŌåÆ * Evidence generator ŌĆö assembles a tamper-evident training evidence record
 17ŌåÆ * from a completed (terminal) training session and its modules.
 18ŌåÆ */
 19ŌåÆ
 20ŌåÆimport { getSnapshot } from "../config/index.js";
 21ŌåÆimport { SQLiteAdapter } from "../storage/sqlite-adapter.js";
 22ŌåÆimport type { TrainingModule, TrainingSession } from "../training/schemas.js";
 23ŌåÆimport { SessionRepository } from "../training/session-repository.js";
 24ŌåÆimport { EvidenceRepository } from "./evidence-repository.js";
 25ŌåÆimport { computeContentHash } from "./hash.js";
 26ŌåÆimport type { EvidenceBody, ModuleEvidence, TrainingEvidence } from "./schemas.js";
 27ŌåÆ
 28ŌåÆ// ---------------------------------------------------------------------------
 29ŌåÆ// Constants
 30ŌåÆ// ---------------------------------------------------------------------------
 31ŌåÆ
 32ŌåÆconst TERMINAL_STATUSES = new Set(["passed", "exhausted", "abandoned"]);
 33ŌåÆconst CURRENT_SCHEMA_VERSION = 1;
 34ŌåÆconst SESSIONS_COLLECTION = "training_sessions";
 35ŌåÆ
 36ŌåÆ// ---------------------------------------------------------------------------
 37ŌåÆ// Public API
 38ŌåÆ// ---------------------------------------------------------------------------
