 40ŌåÆ/**
 41ŌåÆ * Generate an immutable evidence record for a terminal training session.
 42ŌåÆ *
 43ŌåÆ * Creates and manages its own storage connection so it is safe to call as a
 44ŌåÆ * fire-and-forget background task without sharing a connection that may be
 45ŌåÆ * closed by the caller.
 46ŌåÆ *
 47ŌåÆ * Idempotent: if evidence already exists for the session, returns the existing record.
 48ŌåÆ * Throws if the session is not in a terminal state (passed, exhausted, abandoned).
 49ŌåÆ */
 50ŌåÆexport async function generateEvidenceForSession(
 51ŌåÆ  tenantId: string,
 52ŌåÆ  sessionId: string,
 53ŌåÆ  dbPath?: string,
 54ŌåÆ): Promise<TrainingEvidence> {
 55ŌåÆ  const storage = new SQLiteAdapter({ dbPath: dbPath ?? process.env.DB_PATH ?? "data/jem.db" });
 56ŌåÆ  await storage.initialize();
 57ŌåÆ
 58ŌåÆ  try {
 59ŌåÆ    const sessionRepo = new SessionRepository(storage);
 60ŌåÆ    const evidenceRepo = new EvidenceRepository(storage);
 61ŌåÆ
 62ŌåÆ    // 1. Load session
 63ŌåÆ    const session = await storage.findById<TrainingSession>(
 64ŌåÆ      tenantId,
 65ŌåÆ      SESSIONS_COLLECTION,
 66ŌåÆ      sessionId,
 67ŌåÆ    );
 68ŌåÆ
 69ŌåÆ    if (!session) {
 70ŌåÆ      throw new Error(`Session '${sessionId}' not found`);
 71ŌåÆ    }
 72ŌåÆ
 73ŌåÆ    if (!TERMINAL_STATUSES.has(session.status)) {
 74ŌåÆ      throw new Error(
 75ŌåÆ        `Session '${sessionId}' is in '${session.status}' state, expected terminal state (passed, exhausted, or abandoned)`,
 76ŌåÆ      );
 77ŌåÆ    }
 78ŌåÆ
 79ŌåÆ    // 2. Idempotency check ŌĆö return existing evidence if already generated
 80ŌåÆ    const existing = await evidenceRepo.findBySessionId(tenantId, sessionId);
 81ŌåÆ    if (existing) {
 82ŌåÆ      return existing;
 83ŌåÆ    }
 84ŌåÆ
 85ŌåÆ    // 3. Load modules
 86ŌåÆ    const modules = await sessionRepo.findModulesBySession(tenantId, sessionId);
 87ŌåÆ
 88ŌåÆ    // 4. Resolve tenant config for thresholds
 89ŌåÆ    const snapshot = getSnapshot();
 90ŌåÆ    const tenant = snapshot?.tenants.get(tenantId);
 91ŌåÆ    const passThreshold = tenant?.settings?.training?.passThreshold ?? 0.7;
 92ŌåÆ    const maxAttempts = tenant?.settings?.training?.maxAttempts ?? 3;
 93ŌåÆ
 94ŌåÆ    // 5. Assemble the evidence body
 95ŌåÆ    const evidenceBody: EvidenceBody = {
 96ŌåÆ      session: {
 97ŌåÆ        sessionId: session.id,
 98ŌåÆ        employeeId: session.employeeId,
 99ŌåÆ        tenantId: session.tenantId,
100ŌåÆ        attemptNumber: session.attemptNumber,
101ŌåÆ        totalAttempts: maxAttempts,
102ŌåÆ        status: session.status as "passed" | "exhausted" | "abandoned",
103ŌåÆ        createdAt: session.createdAt,
104ŌåÆ        completedAt: session.completedAt,
105ŌåÆ      },
106ŌåÆ      policyAttestation: {
107ŌåÆ        configHash: session.configHash,
108ŌåÆ        roleProfileId: session.roleProfileId,
109ŌåÆ        roleProfileVersion: session.roleProfileVersion,
110ŌåÆ        appVersion: session.appVersion,
111ŌåÆ        passThreshold,
112ŌåÆ        maxAttempts,
113ŌåÆ      },
114ŌåÆ      modules: modules.map((m) => buildModuleEvidence(m)),
115ŌåÆ      outcome: {
116ŌåÆ        aggregateScore: session.aggregateScore,
117ŌåÆ        passed: session.status === "passed" ? true : session.status === "abandoned" ? null : false,
118ŌåÆ        passThreshold,
119ŌåÆ        weakAreas: session.weakAreas,
120ŌåÆ        moduleScores: modules.map((m) => ({
121ŌåÆ          moduleIndex: m.moduleIndex,
122ŌåÆ          title: m.title,
123ŌåÆ          score: m.moduleScore,
124ŌåÆ        })),
125ŌåÆ      },
126ŌåÆ    };
127ŌåÆ
128ŌåÆ    // 6. Compute content hash for tamper detection
129ŌåÆ    const contentHash = computeContentHash(evidenceBody as unknown as Record<string, unknown>);
130ŌåÆ
131ŌåÆ    // 7. Persist the evidence record
132ŌåÆ    const record = await evidenceRepo.create(tenantId, {
133ŌåÆ      tenantId,
134ŌåÆ      sessionId: session.id,
135ŌåÆ      employeeId: session.employeeId,
136ŌåÆ      schemaVersion: CURRENT_SCHEMA_VERSION,
137ŌåÆ      evidence: evidenceBody,
138ŌåÆ      contentHash,
139ŌåÆ      generatedAt: new Date().toISOString(),
140ŌåÆ    });
141ŌåÆ
142ŌåÆ    return record;
143ŌåÆ  } finally {
144ŌåÆ    await storage.close();
145ŌåÆ  }
146ŌåÆ}
147ŌåÆ
148ŌåÆ// ---------------------------------------------------------------------------
149ŌåÆ// Internal helpers
150ŌåÆ// ---------------------------------------------------------------------------
151ŌåÆ
152ŌåÆ/**
153ŌåÆ * Build a client-safe module evidence record.
154ŌåÆ * Strips `correct` from options and `rubric` from scenarios/questions.
155ŌåÆ */
156ŌåÆfunction buildModuleEvidence(module: TrainingModule): ModuleEvidence {
157ŌåÆ  const scenarios = module.content?.scenarios ?? [];
158ŌåÆ  const quizQuestions = module.content?.quiz?.questions ?? [];
159ŌåÆ
160ŌåÆ  return {
161ŌåÆ    moduleIndex: module.moduleIndex,
162ŌåÆ    title: module.title,
163ŌåÆ    topicArea: module.topicArea,
164ŌåÆ    moduleScore: module.moduleScore,
165ŌåÆ    scenarios: scenarios.map((s) => {
166ŌåÆ      const response = module.scenarioResponses.find((r) => r.scenarioId === s.id);
167ŌåÆ      return {
168ŌåÆ        scenarioId: s.id,
169ŌåÆ        narrative: s.narrative,
170ŌåÆ        responseType: s.responseType,
171ŌåÆ        options: s.options?.map((o) => ({ key: o.key, text: o.text })),
172ŌåÆ        employeeAnswer: {
173ŌåÆ          selectedOption: response?.selectedOption,
174ŌåÆ          freeTextResponse: response?.freeTextResponse,
175ŌåÆ          score: response?.score ?? 0,
176ŌåÆ          llmRationale: response?.llmRationale,
177ŌåÆ          submittedAt: response?.submittedAt ?? module.updatedAt ?? module.createdAt,
178ŌåÆ        },
179ŌåÆ      };
180ŌåÆ    }),
181ŌåÆ    quizQuestions: quizQuestions.map((q) => {
182ŌåÆ      const answer = module.quizAnswers.find((a) => a.questionId === q.id);
183ŌåÆ      return {
184ŌåÆ        questionId: q.id,
185ŌåÆ        questionText: q.text,
186ŌåÆ        responseType: q.responseType,
187ŌåÆ        options: q.options?.map((o) => ({ key: o.key, text: o.text })),
188ŌåÆ        employeeAnswer: {
189ŌåÆ          selectedOption: answer?.selectedOption,
190ŌåÆ          freeTextResponse: answer?.freeTextResponse,
191ŌåÆ          score: answer?.score ?? 0,
192ŌåÆ          llmRationale: answer?.llmRationale,
193ŌåÆ          submittedAt: answer?.submittedAt ?? module.updatedAt ?? module.createdAt,
194ŌåÆ        },
195ŌåÆ      };
196ŌåÆ    }),
197ŌåÆ    completedAt: module.status === "scored" ? module.updatedAt : null,
198ŌåÆ  };
199ŌåÆ}
