15ŌåÆ/**
16ŌåÆ * EvidenceRepository ŌĆö immutable storage for training evidence records.
17ŌåÆ * No update or delete methods: evidence is append-only by design.
18ŌåÆ */
19ŌåÆ
20ŌåÆimport type { StorageAdapter } from "../storage/adapter.js";
21ŌåÆimport type { TrainingEvidence } from "./schemas.js";
22ŌåÆ
23ŌåÆconst EVIDENCE_COLLECTION = "evidence";
24ŌåÆ
25ŌåÆexport interface EvidenceListFilters {
26ŌåÆ  employeeId?: string;
27ŌåÆ  from?: string; // ISO datetime
28ŌåÆ  to?: string; // ISO datetime
29ŌåÆ  outcome?: string; // "passed" | "exhausted" | "abandoned"
30ŌåÆ  limit?: number;
31ŌåÆ  offset?: number;
32ŌåÆ}
33ŌåÆ
34ŌåÆexport class EvidenceRepository {
35ŌåÆ  constructor(private readonly storage: StorageAdapter) {}
36ŌåÆ
37ŌåÆ  async create(tenantId: string, data: Omit<TrainingEvidence, "id">): Promise<TrainingEvidence> {
38ŌåÆ    return this.storage.create<Omit<TrainingEvidence, "id">>(
39ŌåÆ      tenantId,
40ŌåÆ      EVIDENCE_COLLECTION,
41ŌåÆ      data,
42ŌåÆ    ) as Promise<TrainingEvidence>;
43ŌåÆ  }
44ŌåÆ
45ŌåÆ  async findBySessionId(tenantId: string, sessionId: string): Promise<TrainingEvidence | null> {
46ŌåÆ    const results = await this.storage.findMany<TrainingEvidence>(tenantId, EVIDENCE_COLLECTION, {
47ŌåÆ      where: { sessionId },
48ŌåÆ      limit: 1,
49ŌåÆ    });
50ŌåÆ    return results[0] ?? null;
51ŌåÆ  }
52ŌåÆ
53ŌåÆ  async findById(tenantId: string, id: string): Promise<TrainingEvidence | null> {
54ŌåÆ    return this.storage.findById<TrainingEvidence>(tenantId, EVIDENCE_COLLECTION, id);
55ŌåÆ  }
56ŌåÆ
57ŌåÆ  async listByTenant(
58ŌåÆ    tenantId: string,
59ŌåÆ    filters: EvidenceListFilters = {},
60ŌåÆ  ): Promise<{ items: TrainingEvidence[]; total: number }> {
61ŌåÆ    const query: Record<string, unknown> = {};
62ŌåÆ    if (filters.employeeId) {
63ŌåÆ      query.employeeId = filters.employeeId;
64ŌåÆ    }
65ŌåÆ
66ŌåÆ    let results = await this.storage.findMany<TrainingEvidence>(tenantId, EVIDENCE_COLLECTION, {
67ŌåÆ      where: Object.keys(query).length > 0 ? query : undefined,
68ŌåÆ      orderBy: [{ field: "generatedAt", direction: "desc" }],
69ŌåÆ    });
70ŌåÆ
71ŌåÆ    // Post-filter: date range
72ŌåÆ    const fromDate = filters.from;
73ŌåÆ    if (fromDate) {
74ŌåÆ      results = results.filter((r) => r.generatedAt >= fromDate);
75ŌåÆ    }
76ŌåÆ    const toDate = filters.to;
77ŌåÆ    if (toDate) {
78ŌåÆ      results = results.filter((r) => r.generatedAt <= toDate);
79ŌåÆ    }
80ŌåÆ    // Post-filter: outcome
81ŌåÆ    if (filters.outcome) {
82ŌåÆ      results = results.filter((r) => r.evidence.session.status === filters.outcome);
83ŌåÆ    }
84ŌåÆ
85ŌåÆ    const total = results.length;
