31ŌåÆ    return NextResponse.json(
32ŌåÆ      { error: "unauthorized", message: "Not authenticated" },
33ŌåÆ      { status: 401 },
34ŌåÆ    );
35ŌåÆ  }
36ŌåÆ
37ŌåÆ  const role = request.headers.get("x-employee-role") ?? "employee";
38ŌåÆ  if (role === "employee") {
39ŌåÆ    return NextResponse.json(
40ŌåÆ      { error: "forbidden", message: "Admin access required" },
41ŌåÆ      { status: 403 },
42ŌåÆ    );
43ŌåÆ  }
44ŌåÆ
45ŌåÆ  const url = new URL(request.url);
46ŌåÆ  const filterEmployeeId = url.searchParams.get("employeeId") ?? undefined;
47ŌåÆ  const outcome = url.searchParams.get("outcome") ?? undefined;
48ŌåÆ  const from = url.searchParams.get("from") ?? undefined;
49ŌåÆ  const to = url.searchParams.get("to") ?? undefined;
50ŌåÆ  const limit = Math.min(Number.parseInt(url.searchParams.get("limit") ?? "20", 10) || 20, 100);
51ŌåÆ  const offset = Number.parseInt(url.searchParams.get("offset") ?? "0", 10) || 0;
52ŌåÆ
53ŌåÆ  const storage = new SQLiteAdapter({
54ŌåÆ    dbPath: process.env.DB_PATH ?? "data/jem.db",
55ŌåÆ  });
56ŌåÆ  const evidenceRepo = new EvidenceRepository(storage);
57ŌåÆ  await storage.initialize();
58ŌåÆ
59ŌåÆ  try {
60ŌåÆ    const { items, total } = await evidenceRepo.listByTenant(tenantId, {
61ŌåÆ      employeeId: filterEmployeeId,
62ŌåÆ      outcome,
63ŌåÆ      from,
64ŌåÆ      to,
65ŌåÆ      limit,
66ŌåÆ      offset,
67ŌåÆ    });
68ŌåÆ
69ŌåÆ    // Map to summary format (strip full evidence body)
70ŌåÆ    const summaries = items.map((item) => ({
71ŌåÆ      id: item.id,
72ŌåÆ      sessionId: item.sessionId,
73ŌåÆ      employeeId: item.employeeId,
74ŌåÆ      schemaVersion: item.schemaVersion,
75ŌåÆ      contentHash: item.contentHash,
76ŌåÆ      generatedAt: item.generatedAt,
77ŌåÆ      outcome: {
78ŌåÆ        status: item.evidence.session.status,
79ŌåÆ        aggregateScore: item.evidence.outcome.aggregateScore,
80ŌåÆ        passed: item.evidence.outcome.passed,
81ŌåÆ      },
82ŌåÆ    }));
83ŌåÆ
84ŌåÆ    return NextResponse.json({ items: summaries, total, limit, offset }, { status: 200 });
85ŌåÆ  } finally {
