 15ŌåÆ/**
 16ŌåÆ * Compliance upload orchestrator ŌĆö coordinates the evidence upload lifecycle.
 17ŌåÆ *
 18ŌåÆ * Responsibilities:
 19ŌåÆ * - Check if tenant has compliance integration enabled
 20ŌåÆ * - Idempotency check (no duplicate uploads)
 21ŌåÆ * - Render evidence to PDF
 22ŌåÆ * - Execute upload with in-process retry (exponential backoff + jitter)
 23ŌåÆ * - Record ComplianceUpload status to storage
 24ŌåÆ */
 25ŌåÆ
 26ŌåÆimport { getSnapshot } from "../config/index.js";
 27ŌåÆimport { EvidenceRepository } from "../evidence/evidence-repository.js";
 28ŌåÆimport { renderEvidencePdf } from "../evidence/pdf-renderer.js";
 29ŌåÆimport type { StorageAdapter } from "../storage/adapter.js";
 30ŌåÆimport { SprintoProvider } from "./providers/sprinto.js";
 31ŌåÆimport type { ComplianceConfig } from "./schemas.js";
 32ŌåÆimport type { ComplianceProvider, ComplianceProviderConfig, ComplianceUploadRecord } from "./types.js";
 33ŌåÆimport { ComplianceUploadRepository } from "./upload-repository.js";
 34ŌåÆ
 35ŌåÆ// ---------------------------------------------------------------------------
 36ŌåÆ// Provider registry
 37ŌåÆ// ---------------------------------------------------------------------------
 38ŌåÆ
 39ŌåÆconst providers: Record<string, ComplianceProvider> = {
 40ŌåÆ  sprinto: new SprintoProvider(),
 41ŌåÆ};
 42ŌåÆ
 43ŌåÆ// ---------------------------------------------------------------------------
 44ŌåÆ// Delay helper
 45ŌåÆ// ---------------------------------------------------------------------------
 46ŌåÆ
 47ŌåÆfunction computeDelay(attempt: number, initialDelayMs: number, maxDelayMs: number): number {
 48ŌåÆ  // Exponential backoff: initialDelay * 2^attempt
 49ŌåÆ  const exponentialDelay = initialDelayMs * 2 ** attempt;
 50ŌåÆ  const cappedDelay = Math.min(exponentialDelay, maxDelayMs);
 51ŌåÆ  // Add jitter: random value between 0 and 50% of the delay
 52ŌåÆ  const jitter = Math.random() * cappedDelay * 0.5;
 53ŌåÆ  return Math.floor(cappedDelay + jitter);
 54ŌåÆ}
 55ŌåÆ
 56ŌåÆfunction sleep(ms: number): Promise<void> {
 57ŌåÆ  return new Promise((resolve) => setTimeout(resolve, ms));
 58ŌåÆ}
 59ŌåÆ
 60ŌåÆ// ---------------------------------------------------------------------------
 61ŌåÆ// Config resolution
 62ŌåÆ// ---------------------------------------------------------------------------
 63ŌåÆ
 64ŌåÆfunction resolveProviderConfig(complianceConfig: ComplianceConfig): ComplianceProviderConfig {
 65ŌåÆ  // Resolve the env var reference for apiKeyRef
 66ŌåÆ  const envVarMatch = complianceConfig.apiKeyRef.match(/^\$\{([A-Z_][A-Z0-9_]*)\}$/);
 67ŌåÆ  const envVarName = envVarMatch?.[1] ?? "";
 68ŌåÆ  const apiKey = process.env[envVarName] ?? "";
 69ŌåÆ
 70ŌåÆ  return {
 71ŌåÆ    provider: complianceConfig.provider,
 72ŌåÆ    apiKey,
 73ŌåÆ    workflowCheckId: complianceConfig.workflowCheckId,
 74ŌåÆ    region: complianceConfig.region,
 75ŌåÆ    retry: {
 76ŌåÆ      maxAttempts: complianceConfig.retry.maxAttempts,
 77ŌåÆ      initialDelayMs: complianceConfig.retry.initialDelayMs,
 78ŌåÆ      maxDelayMs: complianceConfig.retry.maxDelayMs,
 79ŌåÆ    },
 80ŌåÆ  };
 81ŌåÆ}
 82ŌåÆ
 83ŌåÆ// ---------------------------------------------------------------------------
 84ŌåÆ// Public API
 85ŌåÆ// ---------------------------------------------------------------------------
 86ŌåÆ
 87ŌåÆ/**
 88ŌåÆ * Dispatch evidence to the tenant's configured compliance provider.
 89ŌåÆ * Handles retry logic, status recording, and idempotency.
 90ŌåÆ *
 91ŌåÆ * Fire-and-forget safe ŌĆö all errors are caught, logged, and recorded.
 92ŌåÆ */
 93ŌåÆexport async function dispatchUpload(
 94ŌåÆ  tenantId: string,
 95ŌåÆ  evidenceId: string,
 96ŌåÆ  storage: StorageAdapter,
 97ŌåÆ): Promise<void> {
 98ŌåÆ  // 1. Check if tenant has compliance integration enabled
 99ŌåÆ  const snapshot = getSnapshot();
100ŌåÆ  const tenant = snapshot?.tenants.get(tenantId);
101ŌåÆ  const complianceConfig = tenant?.settings?.integrations?.compliance as
102ŌåÆ    | ComplianceConfig
103ŌåÆ    | undefined;
104ŌåÆ
105ŌåÆ  if (!complianceConfig) {
106ŌåÆ    return; // No compliance integration ŌĆö nothing to do
107ŌåÆ  }
108ŌåÆ
109ŌåÆ  const uploadRepo = new ComplianceUploadRepository(storage);
110ŌåÆ  const evidenceRepo = new EvidenceRepository(storage);
111ŌåÆ  const providerConfig = resolveProviderConfig(complianceConfig);
112ŌåÆ
113ŌåÆ  // 2. Resolve provider
114ŌåÆ  const provider = providers[complianceConfig.provider];
115ŌåÆ  if (!provider) {
116ŌåÆ    console.error(
117ŌåÆ      `[compliance] Unknown provider "${complianceConfig.provider}" for tenant "${tenantId}"`,
118ŌåÆ    );
119ŌåÆ    return;
120ŌåÆ  }
121ŌåÆ
122ŌåÆ  // 3. Idempotency check
123ŌåÆ  const existing = await uploadRepo.findByEvidenceId(tenantId, evidenceId, provider.name);
124ŌåÆ  if (existing) {
125ŌåÆ    console.info(
126ŌåÆ      `[compliance] Upload already exists for evidence "${evidenceId}" (status: ${existing.status})`,
127ŌåÆ    );
128ŌåÆ    return;
129ŌåÆ  }
130ŌåÆ
131ŌåÆ  // 4. Load evidence record
132ŌåÆ  const evidence = await evidenceRepo.findById(tenantId, evidenceId);
133ŌåÆ  if (!evidence) {
134ŌåÆ    console.error(
135ŌåÆ      `[compliance] Evidence "${evidenceId}" not found for tenant "${tenantId}"`,
136ŌåÆ    );
137ŌåÆ    await uploadRepo.create(tenantId, {
138ŌåÆ      tenantId,
139ŌåÆ      evidenceId,
140ŌåÆ      sessionId: "",
141ŌåÆ      provider: provider.name,
142ŌåÆ      status: "failed",
143ŌåÆ      attemptCount: 0,
144ŌåÆ      maxAttempts: providerConfig.retry.maxAttempts,
145ŌåÆ      providerReferenceId: null,
146ŌåÆ      lastError: "Evidence record not found",
147ŌåÆ      lastErrorCode: "EVIDENCE_NOT_FOUND",
148ŌåÆ      retryable: false,
149ŌåÆ      createdAt: new Date().toISOString(),
150ŌåÆ      updatedAt: new Date().toISOString(),
151ŌåÆ      completedAt: new Date().toISOString(),
152ŌåÆ    });
153ŌåÆ    return;
154ŌåÆ  }
155ŌåÆ
156ŌåÆ  // 5. Create pending upload record
157ŌåÆ  const now = new Date().toISOString();
158ŌåÆ  const uploadRecord = await uploadRepo.create(tenantId, {
159ŌåÆ    tenantId,
160ŌåÆ    evidenceId,
161ŌåÆ    sessionId: evidence.sessionId,
162ŌåÆ    provider: provider.name,
163ŌåÆ    status: "pending",
164ŌåÆ    attemptCount: 0,
165ŌåÆ    maxAttempts: providerConfig.retry.maxAttempts,
166ŌåÆ    providerReferenceId: null,
167ŌåÆ    lastError: null,
168ŌåÆ    lastErrorCode: null,
169ŌåÆ    retryable: true,
170ŌåÆ    createdAt: now,
171ŌåÆ    updatedAt: now,
172ŌåÆ    completedAt: null,
173ŌåÆ  });
174ŌåÆ
175ŌåÆ  // 6. Render PDF
176ŌåÆ  const tenantDisplayName = tenant?.name ?? tenantId;
177ŌåÆ  let pdfBuffer: Buffer;
178ŌåÆ  try {
179ŌåÆ    pdfBuffer = await renderEvidencePdf(evidence, tenantDisplayName);
180ŌåÆ  } catch (error: unknown) {
181ŌåÆ    const message = error instanceof Error ? error.message : String(error);
182ŌåÆ    console.error(
183ŌåÆ      `[compliance] PDF rendering failed for evidence "${evidenceId}": ${message}`,
184ŌåÆ    );
185ŌåÆ    await updateUploadStatus(uploadRepo, tenantId, uploadRecord, {
186ŌåÆ      status: "failed",
187ŌåÆ      lastError: `PDF rendering failed: ${message}`,
188ŌåÆ      lastErrorCode: "PDF_RENDER_FAILED",
189ŌåÆ      retryable: false,
190ŌåÆ    });
191ŌåÆ    return;
192ŌåÆ  }
193ŌåÆ
194ŌåÆ  // 7. Execute upload with retry loop
195ŌåÆ  const { maxAttempts, initialDelayMs, maxDelayMs } = providerConfig.retry;
196ŌåÆ  let lastResult = uploadRecord;
197ŌåÆ
198ŌåÆ  for (let attempt = 0; attempt < maxAttempts; attempt++) {
199ŌåÆ    if (attempt > 0) {
200ŌåÆ      const delay = computeDelay(attempt - 1, initialDelayMs, maxDelayMs);
201ŌåÆ      console.info(
202ŌåÆ        `[compliance] Retry ${attempt}/${maxAttempts - 1} for evidence "${evidenceId}" ` +
203ŌåÆ          `(provider: ${provider.name}, delay: ${delay}ms)`,
204ŌåÆ      );
205ŌåÆ      await sleep(delay);
206ŌåÆ    }
207ŌåÆ
208ŌåÆ    const result = await provider.uploadEvidence(pdfBuffer, evidence, providerConfig);
209ŌåÆ
210ŌåÆ    if (result.ok) {
211ŌåÆ      console.info(
212ŌåÆ        `[compliance] Upload succeeded for evidence "${evidenceId}" ` +
213ŌåÆ          `(provider: ${provider.name}, attempts: ${attempt + 1})`,
214ŌåÆ      );
215ŌåÆ      await updateUploadStatus(uploadRepo, tenantId, lastResult, {
216ŌåÆ        status: "succeeded",
217ŌåÆ        attemptCount: attempt + 1,
218ŌåÆ        providerReferenceId: result.providerReferenceId,
219ŌåÆ        lastError: null,
220ŌåÆ        lastErrorCode: null,
221ŌåÆ        retryable: false,
222ŌåÆ      });
223ŌåÆ      return;
224ŌåÆ    }
225ŌåÆ
226ŌåÆ    // Update with failure details
227ŌåÆ    lastResult = await updateUploadStatus(uploadRepo, tenantId, lastResult, {
228ŌåÆ      attemptCount: attempt + 1,
229ŌåÆ      lastError: result.errorMessage,
230ŌåÆ      lastErrorCode: result.errorCode,
231ŌåÆ      retryable: result.retryable,
232ŌåÆ    });
233ŌåÆ
234ŌåÆ    console.error(
235ŌåÆ      `[compliance] Upload attempt ${attempt + 1}/${maxAttempts} failed for evidence "${evidenceId}" ` +
236ŌåÆ        `(provider: ${provider.name}, errorCode: ${result.errorCode}, retryable: ${result.retryable})`,
237ŌåÆ    );
238ŌåÆ
239ŌåÆ    // Non-retryable error ŌĆö fail immediately
240ŌåÆ    if (!result.retryable) {
241ŌåÆ      await updateUploadStatus(uploadRepo, tenantId, lastResult, {
242ŌåÆ        status: "failed",
243ŌåÆ      });
244ŌåÆ      return;
245ŌåÆ    }
246ŌåÆ  }
247ŌåÆ
248ŌåÆ  // All retries exhausted
249ŌåÆ  console.error(
250ŌåÆ    `[compliance] All ${maxAttempts} attempts exhausted for evidence "${evidenceId}" ` +
251ŌåÆ      `(provider: ${provider.name})`,
252ŌåÆ  );
253ŌåÆ  await updateUploadStatus(uploadRepo, tenantId, lastResult, {
254ŌåÆ    status: "failed",
255ŌåÆ  });
256ŌåÆ}
257ŌåÆ
258ŌåÆ// ---------------------------------------------------------------------------
259ŌåÆ// Helpers
260ŌåÆ// ---------------------------------------------------------------------------
261ŌåÆ
262ŌåÆasync function updateUploadStatus(
263ŌåÆ  repo: ComplianceUploadRepository,
264ŌåÆ  tenantId: string,
265ŌåÆ  current: ComplianceUploadRecord,
266ŌåÆ  updates: Partial<ComplianceUploadRecord>,
267ŌåÆ): Promise<ComplianceUploadRecord> {
268ŌåÆ  const now = new Date().toISOString();
269ŌåÆ  const completedAt =
270ŌåÆ    updates.status === "succeeded" || updates.status === "failed" ? now : current.completedAt;
271ŌåÆ
272ŌåÆ  return repo.update(tenantId, current.id, {
273ŌåÆ    ...updates,
274ŌåÆ    updatedAt: now,
275ŌåÆ    completedAt,
276ŌåÆ  });
277ŌåÆ}
