 15ŌåÆ/**
 16ŌåÆ * ComplianceUploadRepository ŌĆö storage for compliance upload records.
 17ŌåÆ * Constitution Principle III: Every query is scoped by tenantId.
 18ŌåÆ */
 19ŌåÆ
 20ŌåÆimport type { StorageAdapter } from "../storage/adapter.js";
 21ŌåÆimport type { ComplianceUploadRecord } from "./types.js";
 22ŌåÆ
 23ŌåÆconst COLLECTION = "compliance_uploads";
 24ŌåÆ
 25ŌåÆexport interface ComplianceUploadListFilters {
 26ŌåÆ  status?: string;
 27ŌåÆ  provider?: string;
 28ŌåÆ  limit?: number;
 29ŌåÆ  offset?: number;
 30ŌåÆ}
 31ŌåÆ
 32ŌåÆexport class ComplianceUploadRepository {
 33ŌåÆ  constructor(private readonly storage: StorageAdapter) {}
 34ŌåÆ
 35ŌåÆ  async create(
 36ŌåÆ    tenantId: string,
 37ŌåÆ    data: Omit<ComplianceUploadRecord, "id">,
 38ŌåÆ  ): Promise<ComplianceUploadRecord> {
 39ŌåÆ    return this.storage.create<Omit<ComplianceUploadRecord, "id">>(
 40ŌåÆ      tenantId,
 41ŌåÆ      COLLECTION,
 42ŌåÆ      data,
 43ŌåÆ    ) as Promise<ComplianceUploadRecord>;
 44ŌåÆ  }
 45ŌåÆ
 46ŌåÆ  async findByEvidenceId(
 47ŌåÆ    tenantId: string,
 48ŌåÆ    evidenceId: string,
 49ŌåÆ    provider: string,
 50ŌåÆ  ): Promise<ComplianceUploadRecord | null> {
 51ŌåÆ    const results = await this.storage.findMany<ComplianceUploadRecord>(tenantId, COLLECTION, {
 52ŌåÆ      where: { evidenceId, provider },
 53ŌåÆ      limit: 1,
 54ŌåÆ    });
 55ŌåÆ    return results[0] ?? null;
 56ŌåÆ  }
 57ŌåÆ
 58ŌåÆ  async findById(tenantId: string, id: string): Promise<ComplianceUploadRecord | null> {
 59ŌåÆ    return this.storage.findById<ComplianceUploadRecord>(tenantId, COLLECTION, id);
 60ŌåÆ  }
 61ŌåÆ
 62ŌåÆ  async update(
 63ŌåÆ    tenantId: string,
 64ŌåÆ    id: string,
 65ŌåÆ    data: Partial<ComplianceUploadRecord>,
 66ŌåÆ  ): Promise<ComplianceUploadRecord> {
 67ŌåÆ    return this.storage.update<ComplianceUploadRecord>(
 68ŌåÆ      tenantId,
 69ŌåÆ      COLLECTION,
 70ŌåÆ      id,
 71ŌåÆ      data as Partial<Record<string, unknown>> & Record<string, unknown>,
 72ŌåÆ    ) as Promise<ComplianceUploadRecord>;
 73ŌåÆ  }
 74ŌåÆ
 75ŌåÆ  async listByTenant(
 76ŌåÆ    tenantId: string,
 77ŌåÆ    filters: ComplianceUploadListFilters = {},
 78ŌåÆ  ): Promise<{ items: ComplianceUploadRecord[]; total: number }> {
 79ŌåÆ    const query: Record<string, unknown> = {};
 80ŌåÆ    if (filters.status) {
 81ŌåÆ      query.status = filters.status;
 82ŌåÆ    }
 83ŌåÆ    if (filters.provider) {
 84ŌåÆ      query.provider = filters.provider;
 85ŌåÆ    }
 86ŌåÆ
 87ŌåÆ    const results = await this.storage.findMany<ComplianceUploadRecord>(tenantId, COLLECTION, {
 88ŌåÆ      where: Object.keys(query).length > 0 ? query : undefined,
 89ŌåÆ      orderBy: [{ field: "createdAt", direction: "desc" }],
 90ŌåÆ    });
 91ŌåÆ
 92ŌåÆ    const total = results.length;
 93ŌåÆ    const offset = filters.offset ?? 0;
 94ŌåÆ    const limit = filters.limit ?? 20;
 95ŌåÆ    const items = results.slice(offset, offset + limit);
 96ŌåÆ
 97ŌåÆ    return { items, total };
 98ŌåÆ  }
 99ŌåÆ}
