 33ŌåÆexport interface UploadFailure {
 34ŌåÆ  readonly ok: false;
 35ŌåÆ  readonly retryable: boolean;
 36ŌåÆ  readonly errorCode: string;
 37ŌåÆ  readonly errorMessage: string;
 38ŌåÆ}
