 15ŌåÆ/**
 16ŌåÆ * Sprinto compliance provider ŌĆö uploads evidence PDFs via GraphQL multipart.
 17ŌåÆ * See contracts/sprinto-graphql.md for the full API contract.
 18ŌåÆ */
 19ŌåÆ
 20ŌåÆimport type { TrainingEvidence } from "../../evidence/schemas.js";
 21ŌåÆimport type { ComplianceProvider, ComplianceProviderConfig, UploadResult } from "../types.js";
 22ŌåÆ
 23ŌåÆ// ---------------------------------------------------------------------------
 24ŌåÆ// Regional endpoints
 25ŌåÆ// ---------------------------------------------------------------------------
 26ŌåÆ
 27ŌåÆconst SPRINTO_ENDPOINTS: Record<string, string> = {
 28ŌåÆ  us: "https://app.sprinto.com/dev-api/graphql",
 29ŌåÆ  eu: "https://eu.sprinto.com/dev-api/graphql",
 30ŌåÆ  india: "https://in.sprinto.com/dev-api/graphql",
 31ŌåÆ};
 32ŌåÆ
 33ŌåÆexport function getSprintoEndpoint(region: string): string {
 34ŌåÆ  const url = SPRINTO_ENDPOINTS[region];
 35ŌåÆ  if (!url) {
 36ŌåÆ    throw new Error(`Unknown Sprinto region: ${region}. Expected one of: us, eu, india`);
 37ŌåÆ  }
 38ŌåÆ  return url;
 39ŌåÆ}
 40ŌåÆ
 41ŌåÆ// ---------------------------------------------------------------------------
 42ŌåÆ// GraphQL mutation
 43ŌåÆ// ---------------------------------------------------------------------------
 44ŌåÆ
 45ŌåÆconst UPLOAD_MUTATION = `mutation UploadWorkflowCheckEvidence(
 46ŌåÆ  $workflowCheckPk: UUID!,
 47ŌåÆ  $evidenceRecordDate: DateTime!,
 48ŌåÆ  $evidenceFile: Upload!
 49ŌåÆ) {
 50ŌåÆ  uploadWorkflowCheckEvidence(
 51ŌåÆ    workflowCheckPk: $workflowCheckPk,
 52ŌåÆ    evidenceRecordDate: $evidenceRecordDate,
 53ŌåÆ    evidenceFile: $evidenceFile
 54ŌåÆ  ) {
 55ŌåÆ    message
 56ŌåÆ    workflowCheck {
 57ŌåÆ      evidenceStatus
 58ŌåÆ    }
 59ŌåÆ  }
 60ŌåÆ}`;
 61ŌåÆ
 62ŌåÆ// ---------------------------------------------------------------------------
 63ŌåÆ// Error classification
 64ŌåÆ// ---------------------------------------------------------------------------
 65ŌåÆ
 66ŌåÆconst NON_RETRYABLE_GRAPHQL_ERRORS = new Set([
 67ŌåÆ  "Incorrect check ID",
 68ŌåÆ  "Check in review",
 69ŌåÆ  "Unsupported file format",
 70ŌåÆ]);
 71ŌåÆ
 72ŌåÆfunction classifyHttpError(status: number, statusText: string): UploadResult {
 73ŌåÆ  if (status === 401) {
 74ŌåÆ    return {
 75ŌåÆ      ok: false,
 76ŌåÆ      retryable: false,
 77ŌåÆ      errorCode: "AUTH_FAILED",
 78ŌåÆ      errorMessage: `Sprinto returned 401 Unauthorized: ${statusText}`,
 79ŌåÆ    };
 80ŌåÆ  }
 81ŌåÆ  if (status === 429) {
 82ŌåÆ    return {
 83ŌåÆ      ok: false,
 84ŌåÆ      retryable: true,
 85ŌåÆ      errorCode: "RATE_LIMITED",
 86ŌåÆ      errorMessage: `Sprinto returned 429 Too Many Requests: ${statusText}`,
 87ŌåÆ    };
 88ŌåÆ  }
 89ŌåÆ  // 5xx server errors are retryable
 90ŌåÆ  if (status >= 500) {
 91ŌåÆ    return {
 92ŌåÆ      ok: false,
 93ŌåÆ      retryable: true,
 94ŌåÆ      errorCode: "SERVER_ERROR",
 95ŌåÆ      errorMessage: `Sprinto returned ${status}: ${statusText}`,
 96ŌåÆ    };
 97ŌåÆ  }
 98ŌåÆ  // Other client errors (400, 403, 404, etc.) are not retryable
 99ŌåÆ  return {
100ŌåÆ    ok: false,
101ŌåÆ    retryable: false,
102ŌåÆ    errorCode: "CLIENT_ERROR",
103ŌåÆ    errorMessage: `Sprinto returned ${status}: ${statusText}`,
104ŌåÆ  };
105ŌåÆ}
106ŌåÆ
107ŌåÆfunction classifyGraphQLError(errors: Array<{ message: string }>): UploadResult {
108ŌåÆ  const firstError = errors[0];
109ŌåÆ  const message = firstError?.message ?? "Unknown GraphQL error";
110ŌåÆ
111ŌåÆ  const retryable = !NON_RETRYABLE_GRAPHQL_ERRORS.has(message);
112ŌåÆ  let errorCode = "GRAPHQL_ERROR";
113ŌåÆ
114ŌåÆ  if (message === "Incorrect check ID") {
115ŌåÆ    errorCode = "INVALID_CHECK_ID";
116ŌåÆ  } else if (message === "Check in review") {
117ŌåÆ    errorCode = "CHECK_LOCKED";
118ŌåÆ  } else if (message === "Unsupported file format") {
119ŌåÆ    errorCode = "UNSUPPORTED_FORMAT";
120ŌåÆ  }
121ŌåÆ
122ŌåÆ  return {
123ŌåÆ    ok: false,
124ŌåÆ    retryable,
125ŌåÆ    errorCode,
126ŌåÆ    errorMessage: message,
127ŌåÆ  };
128ŌåÆ}
129ŌåÆ
130ŌåÆ// ---------------------------------------------------------------------------
131ŌåÆ// Provider implementation
132ŌåÆ// ---------------------------------------------------------------------------
133ŌåÆ
134ŌåÆexport class SprintoProvider implements ComplianceProvider {
135ŌåÆ  readonly name = "sprinto";
136ŌåÆ
137ŌåÆ  async uploadEvidence(
138ŌåÆ    pdfBuffer: Buffer,
139ŌåÆ    evidence: TrainingEvidence,
140ŌåÆ    config: ComplianceProviderConfig,
141ŌåÆ  ): Promise<UploadResult> {
142ŌåÆ    const endpoint = getSprintoEndpoint(config.region);
143ŌåÆ    const evidenceDate = evidence.generatedAt.split("T")[0]; // YYYY-MM-DD
144ŌåÆ    const filename = `evidence-${evidence.sessionId}.pdf`;
145ŌåÆ
146ŌåÆ    // Build GraphQL multipart request per spec
147ŌåÆ    const operations = JSON.stringify({
148ŌåÆ      query: UPLOAD_MUTATION,
149ŌåÆ      variables: {
150ŌåÆ        workflowCheckPk: config.workflowCheckId,
151ŌåÆ        evidenceRecordDate: evidenceDate,
152ŌåÆ        evidenceFile: null,
153ŌåÆ      },
154ŌåÆ    });
155ŌåÆ
156ŌåÆ    const map = JSON.stringify({ "0": ["variables.evidenceFile"] });
157ŌåÆ
158ŌåÆ    const formData = new FormData();
159ŌåÆ    formData.append("operations", operations);
160ŌåÆ    formData.append("map", map);
161ŌåÆ    formData.append("0", new Blob([pdfBuffer], { type: "application/pdf" }), filename);
162ŌåÆ
163ŌåÆ    let response: Response;
164ŌåÆ    try {
165ŌåÆ      response = await fetch(endpoint, {
166ŌåÆ        method: "POST",
167ŌåÆ        headers: { "api-key": config.apiKey },
168ŌåÆ        body: formData,
169ŌåÆ      });
170ŌåÆ    } catch (error: unknown) {
171ŌåÆ      const message = error instanceof Error ? error.message : String(error);
172ŌåÆ      return {
173ŌåÆ        ok: false,
174ŌåÆ        retryable: true,
175ŌåÆ        errorCode: "NETWORK_ERROR",
176ŌåÆ        errorMessage: `Network error uploading to Sprinto: ${message}`,
177ŌåÆ      };
178ŌåÆ    }
179ŌåÆ
180ŌåÆ    // HTTP-level errors
181ŌåÆ    if (!response.ok) {
182ŌåÆ      return classifyHttpError(response.status, response.statusText);
183ŌåÆ    }
184ŌåÆ
185ŌåÆ    // Parse GraphQL response
186ŌåÆ    let body: {
187ŌåÆ      data?: {
188ŌåÆ        uploadWorkflowCheckEvidence?: {
189ŌåÆ          message: string;
190ŌåÆ          workflowCheck: { evidenceStatus: string };
191ŌåÆ        };
192ŌåÆ      };
193ŌåÆ      errors?: Array<{ message: string }>;
194ŌåÆ    };
195ŌåÆ
196ŌåÆ    try {
197ŌåÆ      body = (await response.json()) as typeof body;
198ŌåÆ    } catch {
199ŌåÆ      return {
200ŌåÆ        ok: false,
201ŌåÆ        retryable: true,
202ŌåÆ        errorCode: "PARSE_ERROR",
203ŌåÆ        errorMessage: "Failed to parse Sprinto response as JSON",
204ŌåÆ      };
205ŌåÆ    }
206ŌåÆ
207ŌåÆ    // GraphQL application errors
208ŌåÆ    if (body.errors && body.errors.length > 0) {
209ŌåÆ      return classifyGraphQLError(body.errors);
210ŌåÆ    }
211ŌåÆ
212ŌåÆ    // Success
213ŌåÆ    const uploadData = body.data?.uploadWorkflowCheckEvidence;
214ŌåÆ    return {
215ŌåÆ      ok: true,
216ŌåÆ      providerReferenceId: uploadData?.workflowCheck?.evidenceStatus ?? null,
217ŌåÆ      message: uploadData?.message ?? "Evidence uploaded",
218ŌåÆ    };
219ŌåÆ  }
220ŌåÆ}
