 75ŌåÆ  async listByTenant(
 76ŌåÆ    tenantId: string,
 77ŌåÆ    filters: ComplianceUploadListFilters = {},
 78ŌåÆ  ): Promise<{ items: ComplianceUploadRecord[]; total: number }> {
 79ŌåÆ    const query: Record<string, unknown> = {};
 80ŌåÆ    if (filters.status) {
 81ŌåÆ      query.status = filters.status;
 82ŌåÆ    }
 83ŌåÆ    if (filters.provider) {
