function makeEvidence() {
  return {
    id: EVIDENCE_ID,
    tenantId: "test-tenant",
    sessionId: SESSION_ID,
    employeeId: "emp-001",
    schemaVersion: 1,
    contentHash: "sha256-abcdef1234567890",
    generatedAt: ISO,
