}

function makePendingUploadRecord(overrides: Record<string, unknown> = {}) {
  return {
    id: UPLOAD_ID,
    tenantId: "test-tenant",
    evidenceId: EVIDENCE_ID,
    sessionId: SESSION_ID,
    provider: "sprinto",
    status: "pending",
