 15ŌåÆ/**
 16ŌåÆ * Public config API.
 17ŌåÆ * Orchestrates: load ŌåÆ substitute ŌåÆ validate ŌåÆ merge ŌåÆ hash ŌåÆ freeze.
 18ŌåÆ */
 19ŌåÆ
 20ŌåÆimport { readFile } from "node:fs/promises";
 21ŌåÆimport { parse as parseYaml } from "yaml";
 22ŌåÆimport type { ConfigSnapshot, Tenant } from "../tenant/types.js";
 23ŌåÆimport { substituteEnvVars } from "./env-substitute.js";
 24ŌåÆimport { type ConfigErrorDetail, ConfigValidationError } from "./errors.js";
 25ŌåÆimport { computeConfigHash } from "./hasher.js";
 26ŌåÆimport type { ConfigProvider } from "./provider.js";
 27ŌåÆimport { BaseConfigSchema, TenantConfigSchema } from "./schema.js";
 28ŌåÆimport { deepMergeSettings, validateUniqueness } from "./validator.js";
 29ŌåÆ
 30ŌåÆlet currentSnapshot: ConfigSnapshot | null = null;
 31ŌåÆ
 32ŌåÆexport interface LoadConfigOptions {
 33ŌåÆ  env?: Record<string, string | undefined>;
 34ŌåÆ}
 35ŌåÆ
 36ŌåÆ/**
 37ŌåÆ * Load, validate, and freeze the tenant configuration.
 38ŌåÆ * This is the main entry point for the config system.
 39ŌåÆ */
 40ŌåÆexport async function loadConfig(
 41ŌåÆ  provider: ConfigProvider,
 42ŌåÆ  _options: LoadConfigOptions = {},
 43ŌåÆ): Promise<ConfigSnapshot> {
 44ŌåÆ  const errors: ConfigErrorDetail[] = [];
 45ŌåÆ
 46ŌåÆ  // 1. Load and validate defaults
 47ŌåÆ  const rawDefaults = await provider.loadDefaults();
 48ŌåÆ  // We need raw text for env substitution. If provider gives us parsed object,
 49ŌåÆ  // we need to load the raw text separately for substitution.
 50ŌåÆ  // For now, we work with the parsed object directly since FileConfigProvider
 51ŌåÆ  // already parses. We'll handle substitution at the raw text level
 52ŌåÆ  // by re-reading files in a more complete implementation.
 53ŌåÆ  // Actually, let's validate the parsed defaults directly.
 54ŌåÆ  const defaultsResult = BaseConfigSchema.safeParse(rawDefaults);
 55ŌåÆ  if (!defaultsResult.success) {
 56ŌåÆ    for (const issue of defaultsResult.error.issues) {
 57ŌåÆ      errors.push({
 58ŌåÆ        path: issue.path.join("."),
 59ŌåÆ        message: issue.message,
 60ŌåÆ      });
 61ŌåÆ    }
 62ŌåÆ    throw new ConfigValidationError(errors);
 63ŌåÆ  }
 64ŌåÆ  const baseDefaults = defaultsResult.data.defaults;
 65ŌåÆ
 66ŌåÆ  // 2. Load and validate tenant configs
 67ŌåÆ  const rawTenants = await provider.loadTenants();
 68ŌåÆ  const tenants: Tenant[] = [];
 69ŌåÆ
 70ŌåÆ  for (const raw of rawTenants) {
 71ŌåÆ    const tenantResult = TenantConfigSchema.safeParse(raw.content);
 72ŌåÆ    if (!tenantResult.success) {
 73ŌåÆ      for (const issue of tenantResult.error.issues) {
 74ŌåÆ        errors.push({
 75ŌåÆ          file: raw.sourceFile,
 76ŌåÆ          path: issue.path.join("."),
 77ŌåÆ          message: issue.message,
 78ŌåÆ        });
 79ŌåÆ      }
 80ŌåÆ      continue;
 81ŌåÆ    }
 82ŌåÆ
 83ŌåÆ    const data = tenantResult.data;
 84ŌåÆ
 85ŌåÆ    // 3. Deep merge with defaults
 86ŌåÆ    const mergedSettings = deepMergeSettings(baseDefaults, data.settings);
 87ŌåÆ
 88ŌåÆ    const tenant: Tenant = {
 89ŌåÆ      id: raw.tenantId,
 90ŌåÆ      name: data.name,
 91ŌåÆ      hostnames: data.hostnames,
 92ŌåÆ      emailDomains: data.emailDomains,
 93ŌåÆ      settings: mergedSettings,
 94ŌåÆ    };
 95ŌåÆ
 96ŌåÆ    tenants.push(tenant);
 97ŌåÆ  }
 98ŌåÆ
 99ŌåÆ  if (errors.length > 0) {
100ŌåÆ    throw new ConfigValidationError(errors);
101ŌåÆ  }
102ŌåÆ
103ŌåÆ  // 4. Cross-tenant uniqueness validation
104ŌåÆ  validateUniqueness(tenants);
105ŌåÆ
106ŌåÆ  // 5. Build indexes
107ŌåÆ  const hostnameIndex = new Map<string, string>();
108ŌåÆ  const emailDomainIndex = new Map<string, string>();
109ŌåÆ
110ŌåÆ  for (const tenant of tenants) {
111ŌåÆ    for (const hostname of tenant.hostnames) {
112ŌåÆ      hostnameIndex.set(hostname.toLowerCase(), tenant.id);
113ŌåÆ    }
114ŌåÆ    for (const domain of tenant.emailDomains) {
115ŌåÆ      emailDomainIndex.set(domain.toLowerCase(), tenant.id);
116ŌåÆ    }
117ŌåÆ  }
118ŌåÆ
119ŌåÆ  // 6. Compute hash
120ŌåÆ  const configHash = computeConfigHash(tenants);
121ŌåÆ
122ŌåÆ  // 7. Build and freeze snapshot
123ŌåÆ  const tenantsMap = new Map<string, Tenant>();
124ŌåÆ  for (const tenant of tenants) {
125ŌåÆ    tenantsMap.set(tenant.id, Object.freeze(tenant));
126ŌåÆ  }
127ŌåÆ
128ŌåÆ  const snapshot: ConfigSnapshot = Object.freeze({
129ŌåÆ    tenants: tenantsMap,
130ŌåÆ    hostnameIndex,
131ŌåÆ    emailDomainIndex,
132ŌåÆ    configHash,
133ŌåÆ    loadedAt: new Date(),
134ŌåÆ  });
135ŌåÆ
136ŌåÆ  currentSnapshot = snapshot;
137ŌåÆ  return snapshot;
138ŌåÆ}
