 15ŌåÆ/**
 16ŌåÆ * Environment variable substitution for config files.
 17ŌåÆ * Supports ${VAR} and ${VAR:-default} syntax.
 18ŌåÆ * Runs on raw YAML/JSON text BEFORE parsing.
 19ŌåÆ */
 20ŌåÆ
 21ŌåÆimport { ConfigError } from "./errors.js";
 22ŌåÆ
 23ŌåÆconst ENV_VAR_PATTERN = /\$\{([^}]+)\}/g;
 24ŌåÆ
 25ŌåÆconst SENSITIVE_PATTERNS = [/_SECRET$/i, /_KEY$/i, /_PASSWORD$/i, /_TOKEN$/i];
 26ŌåÆ
 27ŌåÆexport interface SubstitutionResult {
 28ŌåÆ  text: string;
 29ŌåÆ  sensitiveVars: ReadonlySet<string>;
 30ŌåÆ}
 31ŌåÆ
 32ŌåÆ/**
 33ŌåÆ * Check whether an env var name matches any denylist pattern.
 34ŌåÆ */
 35ŌåÆfunction isSensitiveVar(varName: string): boolean {
 36ŌåÆ  return SENSITIVE_PATTERNS.some((pattern) => pattern.test(varName));
 37ŌåÆ}
 38ŌåÆ
 39ŌåÆ/**
 40ŌåÆ * Substitute ${VAR} and ${VAR:-default} references in raw text.
 41ŌåÆ * @throws ConfigError if a referenced variable is missing and has no default.
 42ŌåÆ */
 43ŌåÆexport function substituteEnvVars(
 44ŌåÆ  text: string,
 45ŌåÆ  sourceFile: string,
 46ŌåÆ  env: Record<string, string | undefined> = process.env as Record<string, string | undefined>,
 47ŌåÆ): SubstitutionResult {
 48ŌåÆ  const errors: ConfigError[] = [];
 49ŌåÆ  const sensitiveVars = new Set<string>();
 50ŌåÆ
 51ŌåÆ  const result = text.replace(ENV_VAR_PATTERN, (match, expr: string) => {
 52ŌåÆ    const defaultSepIndex = expr.indexOf(":-");
 53ŌåÆ    let varName: string;
 54ŌåÆ    let defaultValue: string | undefined;
 55ŌåÆ
 56ŌåÆ    if (defaultSepIndex !== -1) {
 57ŌåÆ      varName = expr.slice(0, defaultSepIndex);
 58ŌåÆ      defaultValue = expr.slice(defaultSepIndex + 2);
 59ŌåÆ    } else {
 60ŌåÆ      varName = expr;
 61ŌåÆ    }
 62ŌåÆ
 63ŌåÆ    if (isSensitiveVar(varName)) {
 64ŌåÆ      sensitiveVars.add(varName);
 65ŌåÆ    }
 66ŌåÆ
 67ŌåÆ    const value = env[varName];
 68ŌåÆ    if (value !== undefined) {
 69ŌåÆ      return value;
 70ŌåÆ    }
 71ŌåÆ
 72ŌåÆ    if (defaultValue !== undefined) {
 73ŌåÆ      return defaultValue;
 74ŌåÆ    }
 75ŌåÆ
 76ŌåÆ    errors.push(
 77ŌåÆ      new ConfigError({
 78ŌåÆ        file: sourceFile,
 79ŌåÆ        message: `Unresolved environment variable: \${${varName}}`,
 80ŌåÆ      }),
 81ŌåÆ    );
 82ŌåÆ    return match;
 83ŌåÆ  });
 84ŌåÆ
 85ŌåÆ  if (errors.length > 0) {
 86ŌåÆ    const firstError = errors[0];
 87ŌåÆ    if (firstError) throw firstError;
 88ŌåÆ  }
 89ŌåÆ
 90ŌåÆ  return { text: result, sensitiveVars };
 91ŌåÆ}
 92ŌåÆ
 93ŌåÆ/**
 94ŌåÆ * Redact sensitive values in a config object for logging.
 95ŌåÆ * Replaces values of keys matching sensitive patterns with [REDACTED].
 96ŌåÆ */
 97ŌåÆexport function redactSensitiveValues(
 98ŌåÆ  obj: Record<string, unknown>,
 99ŌåÆ  sensitiveVars: ReadonlySet<string>,
100ŌåÆ): Record<string, unknown> {
101ŌåÆ  const redacted: Record<string, unknown> = {};
102ŌåÆ  for (const [key, value] of Object.entries(obj)) {
103ŌåÆ    if (typeof value === "object" && value !== null && !Array.isArray(value)) {
104ŌåÆ      redacted[key] = redactSensitiveValues(value as Record<string, unknown>, sensitiveVars);
