107ŌåÆ      for (const varName of sensitiveVars) {
108ŌåÆ        const envValue = process.env[varName];
109ŌåÆ        if (envValue && value.includes(envValue)) {
110ŌåÆ          isRedacted = true;
111ŌåÆ          break;
112ŌåÆ        }
113ŌåÆ      }
